PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE files (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            filename TEXT NOT NULL,
            hash_sha256 TEXT UNIQUE NOT NULL,
            path TEXT NOT NULL,
            detected_date DATETIME NOT NULL
        );
CREATE TABLE memories (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            file_id INTEGER NOT NULL,
            raw_text TEXT,
            visual_date TEXT,
            legal_classification TEXT,
            summary TEXT,
            entities TEXT,
            topics TEXT,
            importance INTEGER,
            connections TEXT,
            FOREIGN KEY (file_id) REFERENCES files (id)
        );
CREATE TABLE forensic_metadata (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            file_id INTEGER NOT NULL UNIQUE,
            creation_date TEXT,
            gps_location TEXT,
            chronological_certainty_index INTEGER,
            FOREIGN KEY (file_id) REFERENCES files (id)
        );
CREATE TABLE hallazgos_proactivos (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            file_id INTEGER,
            hash_sha256 TEXT NOT NULL,
            filename TEXT NOT NULL,
            path TEXT NOT NULL,
            file_type TEXT,
            descripcion_escena TEXT,
            texto_verbatim TEXT,
            fecha_visible TEXT,
            patrones_detectados TEXT,
            clasificacion_violencia TEXT,
            valor_probatorio INTEGER,
            resumen_pericial TEXT,
            personas_identificadas TEXT,
            fundamento_legal TEXT,
            conexiones TEXT,
            filtro_estrategico TEXT,
            fecha_analisis TEXT NOT NULL,
            FOREIGN KEY (file_id) REFERENCES files(id)
        );
DELETE FROM sqlite_sequence;
COMMIT;
