INSERT INTO memories VALUES(1,481,'Extracto de Demanda Familiar. Expediente 1784/2022. Actor: RENE IVAN ANZORENA HERNANDEZ. Demandada: VIRIDIANA LOPEZ VALENZUELA.','2022-10-17 12:01','Violencia Psicoemocional, Violencia Física, Violencia Patrimonial, Violencia Económica','Demanda de Guarda y Custodia. El actor señala episodios de celotipia, amenazas de daño a bienes (refrigerador, computadora), violencia psicoemocional, gritos y actitud agresiva frente a su hija. También refiere omisión de pago a favor del sustento de la menor, catalogándose como violencia económica (Inconsistencia: Demandada tiene ingresos pero omite su obligación solidaria). Pilar rector: Interés Superior de la Niñez y Autonomía Progresiva de su hija (considerada de 15 años).','RENE IVAN ANZORENA HERNANDEZ (Actor), VIRIDIANA LOPEZ VALENZUELA (Demandada), I. A. L. (Hija menor)','Guarda y Custodia, Pensión Alimenticia, Celotipia, Violencia Patrimonial, Violencia Económica',10,'{"personas": ["RENE IVAN ANZORENA HERNANDEZ", "VIRIDIANA LOPEZ VALENZUELA", "I.A.L."], "eventos_referidos": ["Incidente del 1 de Octubre (2022) - Amenazas de da\u00f1o a bienes", "Intervenci\u00f3n de Seguridad P\u00fablica"], "etiquetas": ["Hechos Probados", "Ancla de Verdad"]}');
INSERT INTO memories VALUES(2,1,'Texto extraído de la imagen: ''SELCO'', ''Sektor 470''. En el fondo se aprecia un letrero amarillo que parece decir ''ÁREA DE PRODUCCIÓN'' y ''MAQUINADO''. Hay etiquetas de advertencia de seguridad con pictogramas de peligro en la maquinaria.',NULL,'Ninguna','La imagen muestra a un hombre adulto operando una máquina de corte industrial (seccionadora marca SELCO, modelo Sektor 470) en lo que parece ser una fábrica de muebles o taller de carpintería. El sujeto utiliza equipo de seguridad básico (casco rojo y chaleco naranja). No se observa ningún acto de violencia física o emocional en la escena. En el contexto de un caso legal, esta imagen podría servir como evidencia de actividad laboral y capacidad económica del sujeto.','Sujeto masculino (trabajador), SELCO (Marca de maquinaria), Fábrica/Taller de carpintería','Actividad laboral, Operación de maquinaria pesada, Entorno industrial',2,'{"personas": ["Sujeto en la imagen (posible progenitor/agresor)"], "eventos_referidos": ["Desempe\u00f1o de labores remuneradas"]}');
INSERT INTO memories VALUES(3,2,'La imagen muestra a un hombre adulto mayor en un taller de carpintería. El individuo viste una camisa de rayas finas y está utilizando un taladro eléctrico de color amarillo para trabajar sobre una estructura de madera compuesta por listones (posiblemente un mueble o una rejilla). En el fondo se aprecian diversos tablones de madera recargados contra una pared y herramientas propias de un oficio de ebanistería. No hay texto ni diálogos presentes en la imagen.',NULL,'Ninguna','Fotografía de un hombre realizando labores de carpintería. La imagen documenta una actividad laboral o productiva, sin que se aprecie visualmente ningún acto de violencia física, psicológica o de otra índole de manera explícita.','Hombre adulto, Taller de carpintería','Carpintería, Oficio, Uso de herramientas',2,'{"personas": ["Sujeto masculino (identidad por confirmar)"], "eventos_referidos": ["Actividad laboral cotidiana"]}');
INSERT INTO memories VALUES(4,3,'Texto visible en la imagen: ''SELCO'', ''Sektor 470''. Señalética de seguridad: icono de uso obligatorio de protección auditiva, etiquetas de advertencia de riesgo mecánico en las manos.',NULL,'Ninguna','La imagen muestra a un hombre trabajando en un entorno industrial o taller de carpintería. Se encuentra operando una máquina cortadora de tableros marca SELCO, modelo Sektor 470. El individuo viste equipo de seguridad (casco rojo, chaleco naranja reflectante, cubrebocas). No se observa ningún acto de violencia física, psicológica o de otro tipo en la escena capturada.','Persona del sexo masculino (trabajador), Maquinaria SELCO Sektor 470, Taller o fábrica','Actividad laboral, Operación de maquinaria, Seguridad industrial',1,'{"personas": ["Sujeto en la imagen"], "eventos_referidos": ["Actividad laboral cotidiana"]}');
INSERT INTO memories VALUES(5,4,'XCEX2510.JPG: La imagen muestra una pieza de carpintería en proceso de construcción. Se trata de una estructura de madera clara (posiblemente pino o abedul) que parece ser un baúl, caja o escritorio con una tapa abatible unida por dos bisagras metálicas tipo libro. El entorno es un taller o área de trabajo con suelo de cemento, cables eléctricos y restos de madera.',NULL,'Ninguna','La imagen muestra un mueble de madera en proceso de fabricación. No se observa evidencia directa de daño físico, amenazas, o menoscabo patrimonial en el contenido visual de la fotografía. Representa un objeto doméstico o de trabajo en buen estado.','','carpintería, bienes muebles',1,'{"personas": [], "eventos_referidos": []}');
INSERT INTO memories VALUES(6,5,'La imagen muestra a un hombre de edad avanzada con cabello canoso y camisa de rayas trabajando en lo que parece ser un taller de carpintería. El hombre está inclinado sobre una estructura de madera compuesta por un marco y listones horizontales paralelos, similar a un somier de cama o una reja. En el entorno se aprecian múltiples tablones de madera recargados contra la pared, herramientas de trabajo, un lápiz rojo y amarillo sobre la mesa de trabajo, y lo que parece ser una ventana o hueco en la pared al fondo. No hay texto escrito ni audio asociado a este archivo.',NULL,'Ninguna','La imagen retrata a un hombre realizando labores de carpintería. No se observa en la fotografía ninguna conducta que constituya violencia física, psicoemocional, patrimonial, económica, sexual o vicaria de manera explícita. La relevancia de la imagen en un contexto de violencia familiar dependería de si se utiliza para acreditar la solvencia económica, la ubicación del sujeto o su actividad laboral.','Hombre adulto mayor, Taller de carpintería','Carpintería, Trabajo manual, Ensamblaje de muebles',2,'{"personas": ["Sujeto masculino (posible figura paterna o familiar)"], "eventos_referidos": ["Actividad laboral o de oficio"]}');
INSERT INTO memories VALUES(7,6,'La imagen muestra una pieza de mobiliario artesanal fabricada en madera clara (posiblemente pino o MDF con chapa de madera). El mueble consta de una base inferior cerrada tipo baúl o cajón grande, montada sobre ruedas metálicas con base de goma. En la parte superior, tiene un respaldo formado por listones de madera dispuestos horizontalmente, del cual se desprenden dos repisas sostenidas por soportes o escuadras metálicas negras. Al fondo se aprecian más piezas de madera recargadas en la pared y una superficie de cartón en el suelo, lo que sugiere un entorno de taller o carpintería.',NULL,'Ninguna','Fotografía de un mueble de madera tipo estantería con baúl integrado sobre ruedas, ubicado en un taller. No se observa evidencia visual directa de actos de violencia, agresiones o daños materiales que sugieran vulneración de derechos o violencia de género en el contenido de la imagen por sí sola.','','mobiliario, bienes muebles, carpintería',1,'{"personas": [], "eventos_referidos": []}');
INSERT INTO memories VALUES(8,7,'No se observa texto escrito ni caracteres OCR en la imagen. El contenido visual muestra un mueble de madera clara, posiblemente pino, que consiste en un cajón rectangular profundo en la base y una estructura vertical alta compuesta por listones horizontales espaciados (tipo celosía o espaldera) en la parte posterior. El mueble está equipado con ruedas giratorias en la base y se encuentra sobre láminas de cartón en lo que parece ser un taller o garaje.',NULL,'Ninguna','La imagen muestra un objeto de carpintería (posiblemente una jardinera con celosía o un separador de ambientes) en un entorno de construcción. De forma aislada, la imagen no presenta evidencia directa de actos de violencia física, psicológica o de otro tipo según el catálogo de la Ley General de Acceso.','','carpintería, mobiliario, construcción',1,'{"personas": [], "eventos_referidos": []}');
INSERT INTO memories VALUES(9,8,'La imagen no contiene texto ni audio. Descripción visual: Un taller o almacén con diversos materiales de madera. Se observan tablones de diferentes tamaños apoyados contra una pared, una estructura de madera tipo rejilla (posiblemente un marco o parte de un mueble) y, en el primer plano, una pieza de mobiliario de madera clara con ruedas metálicas (garruchas) atornilladas en la base. El entorno sugiere un área de construcción o carpintería.',NULL,'Ninguna','Fotografía de un entorno de carpintería o almacenamiento de madera. No se visualizan personas, lesiones, daños intencionales evidentes ni contenido que sugiera directamente un acto de violencia bajo las categorías de la Ley General de Acceso de las Mujeres a una Vida Libre de Violencia.','Taller de carpintería/Almacén','Madera, Herramientas, Mobiliario',1,'{"personas": [], "eventos_referidos": []}');
INSERT INTO memories VALUES(10,9,'Imagen sin texto legible. El archivo visual muestra la parte superior y lateral de un mueble de madera clara, posiblemente un baúl o caja de almacenamiento en proceso de construcción, ubicado en un entorno de taller.',NULL,'Ninguna','La imagen muestra un objeto de carpintería (mueble de madera) en un taller. No se identifican elementos visuales que constituyan evidencia directa de violencia de género, familiar o contra menores en esta fotografía específica.','Mueble de madera, Taller/Carpintería','Construcción de muebles, Propiedad',1,'{"personas": [], "eventos_referidos": []}');
INSERT INTO memories VALUES(11,10,replace('IO\núlt. vez ayer 23:47\n[Imagen de un perro negro con mirada fija]\nAyer 16:00\nVerduras\n-calabaza\n-tomate\n-jitomate\n-cebolla\n-espinaca\n-cilantro\n-cebolla\nFruta\n-Manzana\n-plátano\n-tamarindo\n-tejocote\n-canela\n-Manzana amarilla\n-caña\n-aguacate\n-limon\n-piña\n-papaya\n-fresa\nCarne\n-pollo','\n',char(10)),NULL,'Ninguna','El archivo IMG_9636.PNG es una captura de pantalla de una conversación de WhatsApp con el contacto ''IO''. El contenido muestra el envío de una imagen de una mascota y una lista detallada de compras (mandado) que incluye verduras, frutas y carne. No se identifica lenguaje violento, amenazas o conductas que encuadren directamente en los tipos de violencia descritos por la Ley en este fragmento específico.','IO (Contacto), Persona receptora del mensaje','Lista de víveres, Abastecimiento del hogar, Alimentación',1,'{"personas": ["IO"], "eventos_referidos": ["Gesti\u00f3n cotidiana del hogar"]}');
INSERT INTO memories VALUES(12,11,replace('IO (últ. vez ayer 23:47)\n19:27 - Emisor: que te compre pero hay que ir por ella\n19:30 - IO: [Sticker de personaje ''Flork'' con fórmulas matemáticas, expresando confusión o duda]\n19:30 - Emisor: Entonces? Les mando dinero!\n19:31 - Emisor: ?\n19:34 - Emisor: Te pregunto porque es la solución que te puedo dar ahorita\n19:35 - Emisor: Les estoy llamando paro no contestan en departamento ni en el teléfono 🤔\n19:36 - Emisor: Entonces que hacemos?\n19:38 - Emisor: [Sticker de Homero Simpson pensativo]','\n',char(10)),NULL,'Violencia Psicoemocional','Captura de pantalla de una conversación de WhatsApp donde el emisor intenta coordinar la compra y entrega de un artículo o servicio para una tercera persona (presumiblemente la hija). El emisor muestra frustración ante la falta de respuesta clara y la indiferencia de ''IO'', quien responde con un sticker evasivo y deja de contestar mensajes y llamadas, obstruyendo la resolución de una necesidad económica o logística.','IO (Contacto), Hija (Referenciada implícitamente como ''ella''), Emisor (Usuario del teléfono)','Falta de comunicación, Gestión de recursos económicos, Indiferencia, Necesidades de la menor',6,'{"personas": ["IO", "Hija de 15 a\u00f1os"], "eventos_referidos": ["Intento de env\u00edo de dinero", "Llamadas telef\u00f3nicas no atendidas", "Log\u00edstica de compra para la menor"]}');
INSERT INTO memories VALUES(13,12,replace('Chat con IO. Última vez hoy a la(s) 20:12. \n[Imagen 1 - Comprobante de Retiro]: jue 10 de nov. Retiro disponible. 10 noviembre 2022, 16:06:00 h. Fecha de vencimiento: 17 noviembre 2022. Monto: $200.00. Este retiro no genera comisión. Clave de retiro (12 dígitos): 9675 6589 2268. Código de seguridad (4 dígitos): 1955. Puedes compartir esta clave para que otra persona haga el retiro. Hora de envío: 16:07.\n[Imagen 2 - App de Supermercado]: Búsqueda ''pockys''. Resultados para pocky s (801). Glico Galletas Glico Pocky con cubierta sabor chocolate 40 g $35.00. Galletas Glico Pocky cubierta sabor crema fresa 40 g $35.00. Promoción 2 x $90.00.','\n',char(10)),'2022-11-10 16:07','Violencia Económica','Captura de pantalla de un chat de WhatsApp donde el contacto ''IO'' envía un código para retiro de efectivo sin tarjeta por la cantidad de $200.00 MXN. Posteriormente, se muestra una búsqueda de productos comestibles (galletas) en una aplicación de compras. En el contexto de manutención para una adolescente, la suma de $200 es desproporcionadamente baja, sugiriendo una posible restricción de recursos económicos.','IO, Glico','dinero, manutención, control de gastos, alimentos',7,'{"personas": ["IO (Remitente/Agresor probable)"], "eventos_referidos": ["provisi\u00f3n de recursos m\u00ednimos", "compras de subsistencia"]}');
INSERT INTO memories VALUES(14,13,replace('Viridiana (a través del contacto ''IO''): RENE SOY VIRIDIANA (17:33)\nRene: Dime (17:34)\nViridiana: RECUERDA QUE IO DESAYUNA, COME Y CENA, YA NO HAY JABÓN, SUAVIZANTE, JABÓN PASTA. NO TENGO PARA ESOS GASTOS AL IGUAL QUE EL DE LAS MASCOTAS. (17:35)\nRene: Sí, también se pagan colegiaturas, lunch, uniformes, gas, internet, etc. Ya fueron por las cosas del mercado para lo que les di la clave de retiro ? (17:37)\nRene: Para las cosas de IO ambos tenemos que aportar. Que cosa se requiere? hay una lista? Ya hemos hablado al respecto. (17:39)\nViridiana: VUELVO A INSISTIR EN ESCUELA PÚBLICA (17:40)','\n',char(10)),NULL,'Violencia Económica, Violencia Psicoemocional','Conversación de WhatsApp entre Viridiana (remitente) y Rene (receptor) sobre la manutención de una persona menor de edad o adolescente llamada IO. Viridiana reclama falta de recursos para alimentación básica y productos de higiene, así como para las mascotas. Rene responde enumerando los gastos que ya cubre (educación, servicios) y cuestiona el uso de un retiro de efectivo previo. La discusión concluye con Viridiana insistiendo en el cambio a una escuela pública por falta de solvencia.','Rene, Viridiana, IO, Mascotas','manutención, alimentos, educación, gastos del hogar, escuela pública',8,'{"personas": ["Rene (padre/obligado alimentario)", "Viridiana (madre/gestora)", "IO (hija/beneficiaria)"], "eventos_referidos": ["entrega de clave de retiro para mercado", "discusiones previas sobre el tipo de escuela", "acuerdos previos de aportaci\u00f3n mutua"]}');
INSERT INTO memories VALUES(15,14,'20:53 | Buscar | PETTY WOMAN | CALLE PLOMO | Joyería | Parroquia del Sagrado Corazón de Jesús | Tiendas BBB | CALLE PLATINO | Productos de belleza | GIMNASIO MARIAN | Clínica Chac-mol de Pequeñas Especies | CALLE BATOPILAS | PRIVADA HIERRO | AVENIDA FERROCARRIL HIDALGO | CALLE BOLAÑOS | CALLE COBRE | EJE VIAL 1 OTE | Dispositivos | Personas | Dispositivos | Artículos | Yo | Los Jos','null 20:53','Violencia Psicoemocional','Captura de pantalla de la aplicación ''Encontrar'' (Find My) de un dispositivo iOS, mostrando la ubicación en tiempo real de dos dispositivos móviles (iPhones). En un contexto de violencia familiar, este tipo de herramientas suelen utilizarse como mecanismos de vigilancia, acecho y control sobre la movilidad de las víctimas.','Avenida Ferrocarril Hidalgo, Privada Hierro, Gimnasio Marian, Parroquia del Sagrado Corazón de Jesús, Eje Vial 1 Ote, Clínica Chac-mol de Pequeñas Especies','monitoreo, geolocalización, vigilancia, control, acecho',8,'{"dispositivos": ["iPhone 1", "iPhone 2"], "metodolog\u00eda": ["Vigilancia digital", "Seguimiento satelital"]}');
INSERT INTO memories VALUES(16,15,replace('Remitente: Hola, hija (15:33)\nRemitente: Como te sientes? (15:33)\nIO: Bien (15:33)\nIO: Ya me bajo la tos (15:33)\nRemitente: Yo estoy en la farmacia para comprar tus medicinas (15:33)\nRemitente: Ya fueron a comer? (15:34)\nIO: No (15:35)\nRemitente: Quedaste en algo con mamá? (15:35)\nIO: Si sopita (15:36)\nRemitente: Y que más? (15:36)\nIO: Frijoles (15:37)\nRemitente: Provecho (15:42)\nRemitente: Yo ahorita que tenga tus medicina voy para allá y como algo. (15:43)','\n',char(10)),'2022-11-04 15:43','Ninguna','Conversación de chat de WhatsApp entre un progenitor (remitente) y su hija (identificada como ''IO''). La charla gira en torno al estado de salud de la hija (quien se recupera de tos) y el suministro de medicamentos y alimentos. No se aprecia conducta violenta en esta evidencia particular; muestra una dinámica de cuidado y atención a necesidades básicas.','IO (Hija), Remitente (Progenitor/a), Mamá, Farmacia','Salud, Alimentación, Cuidado parental, Medicinas',2,'{"personas": ["hija", "mam\u00e1"], "eventos_referidos": ["estado de enfermedad (tos)", "compra de medicamentos", "coordinaci\u00f3n para comer"]}');
INSERT INTO memories VALUES(17,16,replace('Texto extraído de la imagen IMG_9408.PNG:\n\n[Mensaje entrante - Hoy]: saber como hacerle llegar esos recursos a IO\n[Mensaje saliente - 19:16]: Si quieres que platiquemos y acordemos sobre otros temas con gusto lo hacemos entre asientos, en persona, por teléfono o con abogados o autoridades presentes; no en el teléfono de IO\n[Mensaje entrante (IO) - 19:16]: Sabes que sigo pagando tu deuda y la deuda de la tienda que se quedaron porque yo dependo de mi crédito y trabajo\n[Mensaje entrante (IO) - 19:17]: Entonces has lo que tú responsabilidad te dicte\n[Mensaje entrante (IO) - 19:17]: Buena noche\n[Mensaje saliente - 19:17] (Respuesta a: ''Sabes que sigo pagando tu deuda...''): A mi no me incluyas en nada de la tienda porque desde que se abrió tu tienda y hasta el día de hoy solo fui tú trabajador gratis y fuera de eso nada tuve ni tengo que ver en ello','\n',char(10)),'null','Violencia Económica, Violencia Patrimonial, Violencia Vicaria, Violencia Psicoemocional','La conversación muestra un conflicto económico relacionado con una tienda y deudas. El emisor presiona a la receptora reclamando el pago de deudas, mientras que ella alega haber sido explotada laboralmente (''trabajador gratis''). Un punto crítico es que el conflicto se desarrolla a través del teléfono de ''IO'' (presumiblemente la hija menor de 15 años), lo cual es señalado por la receptora como un canal inapropiado, sugiriendo el uso de abogados o autoridades.','IO (Presunta hija de 15 años), Emisor (Presunto padre/agresor), Receptora (Presunta madre/víctima), Abogados, Autoridades','deudas, explotación laboral, uso de intermediarios menores, límites de comunicación, gestión de recursos',9,'{"personas": ["IO", "abogados"], "eventos_referidos": ["apertura de una tienda", "historial de trabajo no remunerado", "pago de deudas bancarias/cr\u00e9dito"]}');
INSERT INTO memories VALUES(18,17,replace('[IO]: Ahorita no . (22:00)\n[Usuario]: (Respondiendo a ''Ahorita no .'') Está bien. Te quiero mucho. (22:01)\n[Usuario]: No sé si ya vas a dormir pero que pases buena noche (22:01)\n[IO]: (Imagen con dos mochilas SwissBrand en oferta) BACKPACK ROSA PASTEL LOGO ESTAMPADO UMBRO SWISSBRAND - UNICO $717.45 $279.80; BACKPACK LILA PLACA LOGO UMBRO SWISSBRAND - UNICO $717.45 $279.80 (22:22)\n[Usuario]: (Respondiendo a la imagen) Que es ese hija (23:06)\n[Usuario]: ? (23:07)','\n',char(10)),'2022-11-26 22:00','Ninguna','Conversación de WhatsApp entre una persona (presumiblemente padre/madre) y su hija (''IO''). La hija inicialmente rechaza la comunicación (''Ahorita no''). El remitente se despide afectuosamente. Más tarde, la hija envía una captura de pantalla de dos mochilas en oferta, a lo que el remitente pregunta de qué se trata.','IO (Hija), Usuario (Padre/Madre)','comunicación familiar, necesidades materiales, artículos escolares, afecto',3,'{"personas": ["Hija", "Padre/Madre"], "eventos_referidos": ["Solicitud de compra o expresi\u00f3n de deseos materiales"]}');
INSERT INTO memories VALUES(19,18,replace('IO (hija) envía dos fotografías del interior de un refrigerador a las 14:54. En las imágenes se observa el refrigerador casi vacío, conteniendo únicamente un par de verduras, una fruta, condimentos y una bebida. \nMadre (16:18): ''Hola, hija''\nMadre (16:18): ''No me has dicho cómo estás y si podemos hacer FaceTime''\nIO (16:19): ''a''','\n',char(10)),'2022-11-26 16:19','Violencia Económica, Violencia Psicoemocional','La adolescente envía evidencia visual de la carencia de alimentos en su hogar (refrigerador vacío), lo cual constituye un indicador de negligencia o violencia económica que afecta su derecho a la alimentación. La respuesta de la menor (''a'') a los intentos de comunicación de su madre sugiere un estado de apatía, distanciamiento o agotamiento emocional derivado del entorno de precariedad.','IO (Hija, 15 años), Madre (Remitente de los mensajes)','Inseguridad alimentaria, Negligencia, Derecho a la alimentación, Comunicación evasiva',9,'{"personas": ["Madre", "Hija (adolescente)"], "eventos_referidos": ["Desabasto de insumos b\u00e1sicos en el hogar", "Falta de respuesta emocional efectiva"]}');
INSERT INTO memories VALUES(20,19,replace('Chat con IO\nSáb 26 de nov\n12:44 - [Mensaje saliente verde, texto parcial]: ...casa y atenderte por lo que tramitó tu mamá\n12:45 - RENE, soy Viridiana ¿Vas a enviar dinero para compra de sus comidas?\n12:51 - No tuve una respuesta tuya, le regreso a IO su teléfono. Gracias\n14:54 - [Fotografías de un refrigerador casi vacío, mostrando estantes desocupados y una sola pieza de fruta en el cajón inferior].','\n',char(10)),'2022-11-26 14:54','Violencia Económica, Violencia Patrimonial, Vulneración de los Derechos de Niñas, Niños y Adolescentes','Viridiana contacta a Rene (presumiblemente el progenitor) a través del teléfono de ''IO'' para solicitar dinero para la alimentación. Ante la falta de respuesta, Viridiana envía evidencia fotográfica de un refrigerador vacío, demostrando la carencia de suministros básicos y el incumplimiento de las obligaciones de asistencia alimentaria.','Viridiana (Emisora/Madre), Rene (Destinatario/Padre), IO (Posible hija/hijo menor de edad, titular del teléfono), Mamá de Rene (Mencionada en el texto verde)','falta de alimentos, solicitud de pensión alimenticia, omisión de cuidados, evidencia de carestía',10,'{"personas": ["Rene", "Viridiana", "IO"], "eventos_referidos": ["Tr\u00e1mite legal previo realizado por la madre de Rene", "Uso del dispositivo del menor para comunicaci\u00f3n urgente"]}');
INSERT INTO memories VALUES(21,20,replace('[19:58] Progenitor: Porfa me cientas cuando llegues para saber que estás bien .\n[19:58] Hija: Sip .\n[20:57] Progenitor: Hola hija. Ya todo bien? Estas en casa ?\n[21:55] Progenitor: Hija, por favor dime si estás bien y en casa\n[21:58] Hija: Si toy bien .\n[21:58] Progenitor: Ok, quieres platicar ?\n[21:59] Progenitor: Hija, me preocupa mucho no poder darte lo que siempre te he dado ni poder estar ahí para apoyarte .\n[22:00] Hija (en respuesta a ''Ok, quieres platicar ?''): Ahorita no .','\n',char(10)),'2022-11-26 22:00','Violencia Psicoemocional, Violencia Económica','Conversación de WhatsApp donde un progenitor manifiesta ansiedad por el paradero de su hija y expresa explícitamente una carencia en su capacidad de proveer sustento económico y presencia física (''no poder darte lo que siempre te he dado ni poder estar ahí''). La menor responde de manera escueta y establece un límite al rechazar la comunicación profunda, lo cual refleja una afectación en el vínculo afectivo y posibles repercusiones en su bienestar por la situación económica o familiar referida.','Hija (identificada como ''IO''), Progenitor (Remitente de los mensajes verdes)','seguridad de la menor, sustento económico, ausencia parental, barreras de comunicación',8,'{"personas": ["hija de 15 a\u00f1os", "progenitor"], "eventos_referidos": ["cambio en la situaci\u00f3n de proveedur\u00eda econ\u00f3mica", "posible restricci\u00f3n de convivencia o impedimento de presencia f\u00edsica"]}');
INSERT INTO memories VALUES(22,21,replace('[19:17] Emisor: tu trabajador gratis y fuera de eso nada tuve ni [Hoy] que ver en ello\n[19:18] Emisor (respondiendo a IO): Entonces has lo que tú responsabilidad te dicte. Por eso te pregunto nuevamente ¿cómo le hago llegar a IO el recurso sin que sea un problema contigo?\n[19:19] Receptor: Afortunadamente hay más personas de testigos. Buena noche. Le regreso a IO su teléfono\n[19:19] Emisor: Por favor entiende que lo se trata de ti ni de mi no de uretras diferencias, se trata de IO. Como hago llegar el dinero a IO para sus compras de la semana?\n[19:20] Emisor (corrección): *no se trata de ti ni de nuestras diferencias, se trata de IO\n[Parte inferior cortada] Receptor: Lo entiendo por eso lo quiso arreglar...','\n',char(10)),'null','Violencia Económica, Violencia Vicaria, Violencia Psicoemocional','Captura de pantalla de una conversación de WhatsApp donde el emisor intenta acordar la entrega de recursos económicos para la manutención (compras de la semana) de una menor identificada como ''IO''. El interlocutor, quien tiene posesión del teléfono de la menor, muestra una actitud evasiva y defensiva, mencionando la existencia de ''testigos''. Se evidencia un conflicto entre adultos que obstaculiza el flujo de recursos básicos para la adolescente y una manipulación de sus canales de comunicación.','IO (Adolescente de 15 años), Emisor (Probable padre/deudor alimentario), Interlocutor (Persona en posesión del teléfono de IO, probable madre/cuidadora), Testigos (mencionados)','Manutención económica, Obstaculización de recursos, Control de comunicación de la menor, Conflictividad parental',9,'{"personas": ["IO", "Padre/Emisor", "Madre/Interlocutor"], "eventos_referidos": ["Diferencias personales previas", "Necesidad de sustento semanal (compras)", "Intervenci\u00f3n de terceros (testigos)"]}');
INSERT INTO memories VALUES(23,23,replace('IO: [Imagen de productos Almond Crush y Pocky]\nIO: Quiero ir a Nini so (16:08)\nUsuario: El precio ha de ser padecido (16:08)\nUsuario: *parecido (16:09)\nUsuario: Hola hija (18:19)\nUsuario: Compraron tus pockys? (18:19)\nIO: Mi mamá me va a yevar a minisi (18:28)\nUsuario: Ok (18:29)\nIO: Pasamos por ti? (18:29)\nUsuario: Porfa me avisas cuando vuelvan a casa (18:29)\nUsuario (en respuesta a ''Pasamos por ti?''): No, estoy lanzando unas campaña terminado me voy (18:29)','\n',char(10)),'2022-11-10 18:29','Ninguna','Intercambio de mensajes de WhatsApp entre un progenitor y su hija menor de edad. Conversan de manera cotidiana sobre el deseo de comprar golosinas y la logística de transporte, donde la menor informa que su madre la llevará a una tienda (Miniso) y se ofrecen a recoger al interlocutor. No se observa contenido violento explícito en esta interacción.','IO (Hija), Madre (mencionada), Usuario (Padre/Madre), Miniso (establecimiento comercial), Casa','Rutina familiar, Compras, Logística de transporte',2,'{"personas": ["madre", "hija"], "eventos_referidos": ["visita a Miniso", "regreso a casa"]}');
INSERT INTO memories VALUES(24,27,'El archivo FJJR0058.JPG no contiene texto escrito ni audio. Descripción visual: Retrato tipo ''selfie'' de una joven adolescente, presumiblemente la hija de 15 años referida en el caso. Presenta cabello oscuro, mirada directa a la cámara y una expresión facial que denota seriedad, cansancio o tristeza. La iluminación es cenital y el fondo es una pared de color rojizo.',NULL,'Violencia Psicoemocional','La imagen constituye evidencia documental del estado físico y emocional de una persona menor de edad involucrada en un entorno de violencia familiar. Aunque no se observan lesiones físicas evidentes (Violencia Física), su semblante sugiere una afectación emocional, relevante para acreditar la Violencia Psicoemocional en el núcleo familiar.','Adolescente (hija de 15 años)','Estado emocional de la menor, Identidad de la víctima, Interés Superior de la Niñez',9,'{"personas": ["Hija adolescente"], "eventos_referidos": ["Documentaci\u00f3n de impacto emocional en menores"]}');
INSERT INTO memories VALUES(25,31,replace('Transcripción del chat:\n[12:36] tú dime, ya hemos platicado al respecto\n[13:58] Hola, hija\n[14:08] Como sigue tu molestia del pecho?\n[14:08] Te sigue haciendo "dzzzzz"?\n[14:09] Porfa me dices cuando vayan para el médic\n[14:19] Ya salimos, llama\n\nTexto de la Receta Médica en imagen:\nDr. Gabriel Aguilar Piñón - Pediatra y Neumologopediatra\nCédulas Profesionales: 2155708 / 3197336\nReceta Médica - Expediente: 13610 - Fecha: 04/11/2022\nPaciente: Niña IO ANZORENA LOPEZ\nFemenino - 11 años 10 meses 13 días\nPeso: 37 kg - Altura: 144 cm\nPrescripción:\n1.- Macrozit de 1200 mgr dar 7 ml x día a término\n2.- Umckaloabo en solución dar 5 ml cada 8 hrs a término, posteriormente dar Broncho vaxom capsual de 3,5 mgr infantil 1 x día x 10 días x 30 de reposo x 10 días\n3.- ACC de 200 mgr cada 12 hrs x 10 días\n4.- Celestamien NS en solucion dar 7 ml cada 12 hrs x 7 días\n5.- Lometopan de 60 dosis 1 disparo x dia x 30 dias x narina\n6.- Centrum women 1 x día x 30 días\n7.- Isopure 1 toma en las noches\nEdad osea de mano\nCheck Up basico\nUbicación: Otavalo No. 45, Colonia Lindavista C.P. 07300 Méx. D.F.','\n',char(10)),'2022-11-04 14:19','Ninguna','Evidencia de comunicación entre un progenitor y su hija respecto a su estado de salud respiratoria. El progenitor pregunta por síntomas específicos (''dzzzzz'' en el pecho) y solicita ser avisado sobre la consulta médica. La hija responde enviando una receta médica detallada de un neumólogo pediatra que confirma la atención médica recibida el 4 de noviembre de 2022.','IO ANZORENA LOPEZ (Niña/Hija), Dr. Gabriel Aguilar Piñón (Neumólogo Pediatra), Colonia Lindavista, Ciudad de México','salud, atención médica pediátrica, seguimiento parental, medicación',8,'{"personas": ["Hija", "Padre/Madre (remitente)", "M\u00e9dico especialista"], "eventos_referidos": ["Consulta m\u00e9dica por molestia en el pecho", "Tratamiento por afecci\u00f3n respiratoria"]}');
INSERT INTO hallazgos_proactivos VALUES(1,11,'f3b155893c35ec5b59d439becea570c6dff87e8bdda6b35d901d924441fa12cc','IMG_9622.PNG','2022/IMG_9622.PNG','imagen','Captura de pantalla de una conversación de WhatsApp entre el usuario del dispositivo (presuntamente el actor, René Iván Anzorena Hernández) y un contacto registrado como ''IO''. La interfaz muestra una serie de mensajes enviados por el actor intentando coordinar un pago o entrega de dinero y manifestando frustración ante la falta de respuesta telefónica y en el domicilio de la contraparte.',replace('[19:27] Remitente: que te compre pero hay que ir por ella\n[19:30] IO: [Sticker de personaje ''Flork'' con fórmulas matemáticas alrededor, expresando confusión]\n[19:30] Remitente: Entonces? Les mando dinero!\n[19:31] Remitente: ?\n[19:34] Remitente: Te pregunto porque es la solución que te puedo dar ahorita\n[19:35] Remitente: Les estoy llamando paro no contestan en departamento ni en el teléfono 🤔\n[19:36] Remitente: Entonces que hacemos?\n[19:38] Remitente: [Sticker de Homero Simpson con expresión de duda/preocupación]','\n',char(10)),'2022-12-19 01:39','desacato_visitas, violencia_vicaria','Violencia Psicoemocional, Violencia Vicaria',7,'El documento digital acredita la disposición del padre para cumplir con obligaciones económicas y su intento activo de establecer comunicación, el cual es ignorado o respondido de forma evasiva mediante stickers por la contraparte. Se observa un patrón de incomunicación deliberada (''no contestan en departamento ni en el teléfono'') que obstaculiza la coparentalidad. Esta evidencia contradice posibles argumentos de abandono económico por parte del actor.','IO (Contacto receptor), René Iván Anzorena Hernández (Presunto emisor), I.A.L. (Referida como ''ella'')','Código Civil para el Distrito Federal, Artículo 416 Ter (Derecho a la comunicación y convivencia); Ley General de los Derechos de Niñas, Niños y Adolescentes, Artículo 103 (Deberes de crianza y comunicación).','{"hecho_relacionado": "Obstrucción de canales de comunicación directa y presencial en el domicilio.", "patron_previo": "Uso de evasivas para evitar la coordinación de necesidades de la menor."}','APROBADO. La prueba es útil para demostrar la proactividad del padre en el sustento y la actitud obstructiva de la custodia, fundamental para acreditar la alienación o violencia vicaria en la CDMX.','2026-04-02 21:18:33');
INSERT INTO hallazgos_proactivos VALUES(2,13,'de4129cb339d05bad874f90e0fa4f4d7cdba15f63ccdab154c80751a7c45611d','IMG_9434.PNG','2022/IMG_9434.PNG','imagen','Captura de pantalla de una conversación de la aplicación de mensajería WhatsApp. El remitente está guardado bajo el nombre ''IO'', pero el primer mensaje aclara que quien escribe es Viridiana (la demandada). La conversación muestra una disputa sobre la manutención de la menor I.A.L., artículos de limpieza y la educación escolar.',replace('IO en línea\nRENE SOY VIRIDIANA 17:33\nDime 17:34 ✓✓\nRECUERDA QUE IO DESAYUNA, COME Y CENA, YA NO HAY JABÓN, SUAVIZANTE, JABÓN PASTA. NO TENGO PARA ESOS GASTOS AL IGUAL QUE EL DE LAS MASCOTAS. 17:35\n[Mensaje respondido de IO]: RECUERDA QUE IO DESAYUNA, COME Y CENA, YA NO HAY JABÓN, SUAVIZANTE, JABÓN PASTA. NO TENGO PARA ESOS GA...\nSí, también se pagan colegiaturas, lunch, uniformes, gas, internet, etc. Ya fueron por las cosas del mercado para lo que les di la clave de retiro ? 17:37 ✓✓\nPara las cosas de IO ambos tenemos que aportar. Que cosa se requiere? hay una lista? Ya hemos hablado al respecto. 17:38 ✓✓\nVUELVO A INSISTIR EN ESCUELA PÚBLICA 17:38','\n',char(10)),'2022-12-05 17:38','violencia_vicaria, inaccion_educativa','Violencia Económica, Violencia Vicaria',8,'Se observa una dinámica de coacción económica por parte de la demandada hacia el actor, utilizando las necesidades básicas de alimentación e higiene de la menor como herramienta de presión. La demandada amenaza la estabilidad educativa de la adolescente de 15 años al insistir en un cambio a escuela pública como respuesta a supuestas carencias, ignorando las aportaciones ya realizadas por el padre.','René Iván Anzorena Hernández (destinatario/actor), Viridiana López Valenzuela (remitente/demandada), I.A.L. (referida como ''IO'')','Artículos 308, 416 Ter y 444 del Código Civil para el Distrito Federal (relativos a la obligación alimentaria y violencia familiar); Ley General de Acceso de las Mujeres a una Vida Libre de Violencia (Violencia Vicaria).','{"hecho_principal": "Disputa por gastos de manutención", "evidencia_correlacionada": "Mención de claves de retiro para insumos de mercado provistas por el padre, lo que contradice la narrativa de abandono económico."}','APROBADO si construye sustento legal para CDMX 2026. Es evidencia directa de violencia vicaria y económica, además de acreditar que el padre provee activamente recursos (colegiaturas, claves de retiro) que la madre desestima para generar culpa.','2026-04-02 21:19:23');
INSERT INTO hallazgos_proactivos VALUES(3,19,'d775b3ef22d4473b518d2c594db1035acdeb6c19e206117aa61164597ba298a5','IMG_9384.PNG','2022/IMG_9384.PNG','imagen','Captura de pantalla de una conversación de WhatsApp en el dispositivo de la menor (identificada como ''IO''). La interfaz muestra que la madre, Viridiana López Valenzuela, tomó el teléfono de su hija para enviar mensajes directos al padre, René Iván Anzorena Hernández. Se incluyen dos fotografías del interior de un refrigerador que muestra pocos alimentos y suciedad en la base, utilizadas como medio de presión económica.','20:33 | IO últ. vez hoy a la(s) 20:12 | casa y atenderte por lo que tramitó tu mamá sáb 26 de nov 12:44 | RENE, soy Viridiana ¿Vas a enviar dinero para compra de sus comidas? 12:45 | No tuve una respuesta tuya, le regreso a IO su teléfono. Gracias 12:51 | [Imagen de refrigerador con estantes mayormente vacíos o con pocos recipientes] 14:54 | [Imagen de acercamiento al cajón inferior del refrigerador con una sola fruta y manchas líquidas]','2022-11-26 14:54','violencia_vicaria, alienacion_parental','Violencia Vicaria, Violencia Económica, Violencia Psicoemocional',9,'La evidencia demuestra que la demandada vulnera la privacidad y el entorno digital de la menor al utilizar su teléfono personal para confrontar al padre por cuestiones económicas. El envío de fotos del refrigerador utilizando el perfil de la hija constituye una manipulación emocional y el uso de la menor como instrumento de coacción (Violencia Vicaria). Estas acciones impactan negativamente en el derecho de la adolescente a una vida libre de violencia y a mantener un vínculo sano con ambos progenitores.','René Iván Anzorena Hernández (mencionado como RENE), Viridiana López Valenzuela (remitente autodeclarada), I.A.L. (referida como IO)','Código Civil para la CDMX Artículo 323 Septimus (Violencia Vicaria); Ley General de los Derechos de Niñas, Niños y Adolescentes Artículo 13; Ley de Acceso de las Mujeres a una Vida Libre de Violencia de la CDMX.','{"hecho_relacionado": "Uso indebido de dispositivos de comunicación de la menor para fines de conflicto parental y coacción por pensión alimenticia."}','APROBADO. Constituye prueba directa de violencia vicaria y la falta de respeto a la autonomía y privacidad de la menor de 15 años, fundamental para el juicio de Pérdida de Patria Potestad.','2026-04-02 21:21:08');
INSERT INTO hallazgos_proactivos VALUES(4,21,'92039b6098b2c809eada9c97f6dc59fcaab522ce3cfbc7a912705399fa5b7827','IMG_9409.PNG','2022/IMG_9409.PNG','imagen','Captura de pantalla de una conversación de WhatsApp en un dispositivo iOS. El chat se mantiene entre el usuario (identificado como René Iván Anzorena Hernández) y el contacto ''IO'' (I.A.L.). Se observa una intervención de un tercero que utiliza el teléfono de la menor para responder de forma hostil al padre, quien intenta coordinar la entrega de recursos económicos para la adolescente.',replace('20:39\n< 1 IO últ. vez hoy a la(s) 20:12\n[19:17] tu trabajador gratis y fuera de eso nada tuve ni [Hoy] que ver en ello ✔️✔️\n[19:18] René a IO: [Cita: Entonces has lo que tú responsabilidad te dicte] Por eso te pregunto nuevamente ¿cómo le hago llegar a IO el recurso sin que sea un problema contigo ? ✔️✔️\n[19:19] IO (Tercero): Afortunadamente hay más personas de testigos. Buena noche. Le regreso a IO su teléfono\n[19:19] René a IO: Por favor entiende que lo se trata de ti ni de mi no de uretras diferencias, se trata de IO\n[19:19] René a IO: Como hago llegar el dinero a IO para sus compras de la semana? ✔️✔️\n[19:20] René a IO: [Cita: Por favor entiende que lo se trata de ti ni de mi no de uretras diferencias, se trata de IO. Como hago llegar el dinero a IO para sus co...] *no se trata de ti ni de nuestras diferencias, se trata de IO ✔️✔️\n[Mensaje inferior cortado]: Lo entiendo por eso lo quiso arreglar...','\n',char(10)),'2022-12-03 20:39','desacato_visitas, violencia_vicaria, alienacion_parental','Violencia Vicaria, Violencia Psicoemocional, Violencia Económica',9,'La evidencia demuestra una interferencia directa en la comunicación entre el padre y la menor por parte de un tercero (presumiblemente la madre), quien intercepta el dispositivo de la adolescente para confrontar al progenitor. El actor manifiesta una voluntad proactiva de cumplir con sus obligaciones económicas (''recurso para compras de la semana''), la cual es obstaculizada por el entorno de la custodia. Este comportamiento constituye un indicio claro de violencia vicaria y alienación parental al utilizar el canal de comunicación de la menor como herramienta de conflicto.','René Iván Anzorena Hernández (Actor/Remitente), I.A.L. (Alias ''IO'', hija menor de edad), Viridiana López Valenzuela (Persona inferida que intercepta el teléfono)','Código Civil para el Distrito Federal, Artículo 416 Ter (derecho a la convivencia y prohibición de alienación); Ley General de los Derechos de Niñas, Niños y Adolescentes, Artículo 13 (derecho a la intimidad y debida comunicación); Ley de Acceso de las Mujeres a una Vida Libre de Violencia de la CDMX (en materia de Violencia Vicaria para protección del vínculo paterno-filial).','{"interferencia_comunicacion": "La frase ''Le regreso a IO su teléfono'' confirma que la menor no tenía el control de su dispositivo durante el diálogo sobre manutención.", "obstruccion_economica": "El padre pregunta explícitamente cómo entregar el dinero sin generar problemas, evidenciando un patrón de hostilidad previo por parte de la madre."}','APROBADO. Esta prueba es fundamental para acreditar la Violencia Vicaria y la manipulación de los canales de comunicación de la menor, justificando la revisión de la guarda y custodia en favor del interés superior de la adolescente.','2026-04-02 21:22:13');
INSERT INTO hallazgos_proactivos VALUES(5,22,'d0e8c1d0e00e70a762f240406faaf86caba1084a4e53426b5715df9ebec1d595','IMG_9347.PNG','2022/IMG_9347.PNG','imagen','Captura de pantalla de un dispositivo móvil (iPhone) mostrando una conversación de WhatsApp entre el usuario (padre) y el contacto ''IO'' (hija adolescente). Se observa una interacción cotidiana y positiva centrada en el suministro de medicamentos, alimentos y golosinas.',replace('20:26\n1\nIO\núlt. vez hoy a la(s) 20:12\nFrijoles 15:37\nvie 4 de nov\nProvecho 15:42 ✔✔\nYo ahorita que tenga tus medicinas voy para allá y como algo. 15:43 ✔✔\nHola 18:02\nHola hija 18:08 ✔✔\nMe puedes traer unos chcolates de bolitas 18:08\nOk 18:15 ✔✔\nsáb 5 de nov\nHija 9:37 ✔✔\n2 quesadillas o 1 quesadilla y 1 taco? 9:37 ✔✔\nConfírmame en lo que llego, ya estoy por el parque 9:38 ✔✔\n2 quesadilla y 1 taco 9:39\nPor favor 9:39','\n',char(10)),'2022-11-05 09:39','sin_relevancia_procesal','Ninguna',7,'La evidencia digital demuestra un ejercicio activo de la paternidad por parte de René Iván Anzorena Hernández, quien suministra medicamentos y alimentos a su hija I.A.L. La comunicación refleja un vínculo afectivo sano y el cumplimiento de obligaciones de crianza. La menor manifiesta sus necesidades de manera directa, ejerciendo su autonomía progresiva en un entorno de confianza con el progenitor.','René Iván Anzorena Hernández (Padre/Emisor), I.A.L. (Hija/Receptor identificado como IO)','Artículos 414 Bis y 416 Ter del Código Civil para el Distrito Federal (CDMX), relativos al cumplimiento de las obligaciones de crianza y el interés superior del menor.','{"hecho_relevante": "Cumplimiento de obligación alimentaria y de salud.", "contexto": "Contradice posibles alegatos de abandono o desinterés por parte del padre en el proceso de pérdida de patria potestad."}','APROBADO. Aunque no muestra una conducta negativa de la contraparte, es fundamental para acreditar la idoneidad del padre y su involucramiento constante en la vida y salud de la adolescente.','2026-04-02 21:22:57');
INSERT INTO hallazgos_proactivos VALUES(6,31,'c401b5c52797358efacc6e99b4863bd6fb8df2b57a159017fa6fcaf2546c1cf4','IMG_9345.PNG','2022/IMG_9345.PNG','imagen','Captura de pantalla de una conversación de WhatsApp entre el usuario (emisor, René Iván Anzorena Hernández) y un contacto identificado como ''IO'' (la menor I.A.L.). La interfaz muestra una comunicación fluida sobre el estado de salud de la adolescente, quien padece una afección respiratoria. Se adjunta la imagen de una receta médica emitida por un especialista en neumología pediátrica, confirmando una consulta realizada el mismo día.',replace('IO - últ. vez hoy a la(s) 20:12\nvie 4 de nov\n[12:36] tú dime, ya hemos platicado al respecto\n[13:58] Hola, hija\n[14:08] Como sigue tu molestia del pecho?\n[14:08] Te sigue haciendo ''dzzzzz''?\n[14:09] Porfa me dices cuando vayan para el médic\n[14:19] Ya salimos, llama\n[Imagen de receta médica]: Dr. Gabriel Aguilar Piñón, Pediatra y Neumólogo Pediatra. Receta Médica. Paciente: Niña IO ANZORENA LOPEZ. Fecha: 04/11/2022. Edad: 11 años 10 meses 13 días. Prescripción: Macrozit, Umckaloabo, Broncho vaxom, ACC 200 mg, Celestamine NS, Lometopan, Centrum women, Isopure. Firma al calce.','\n',char(10)),'2022-11-04 14:19','sin_relevancia_procesal','Ninguna',7,'La evidencia demuestra un ejercicio activo de la coparentalidad y preocupación del padre por la salud de la menor. La comunicación es directa, afectuosa y centrada en el bienestar médico de la adolescente, quien corresponde informando sobre su consulta. No se observan indicadores de violencia o abandono, sino una dinámica de cuidado funcional.','René Iván Anzorena Hernández (padre/emisor), I.A.L. (menor identificada como IO), Dr. Gabriel Aguilar Piñón (médico)','Artículos 414, 416 y 417 del Código Civil para el Distrito Federal, relativos al cumplimiento de los deberes de cuidado y el derecho a la salud en el ejercicio de la patria potestad.','{"expediente": "1784/2022", "hechos": "Desvirtúa posibles argumentos de abandono moral o falta de interés por parte del progenitor no custodio."}','APROBADO si se utiliza para acreditar el vínculo afectivo y el cumplimiento de obligaciones de cuidado por parte del padre frente a acusaciones de abandono.','2026-04-02 21:27:33');
INSERT INTO hallazgos_proactivos VALUES(7,NULL,'0876758c27dee9a1c9f6d6e5c53cb66b01ad331cacb9ef58e91a9bd8bb221f6e','IMG_3181.PNG','2023/WhatsApp iMessage/IMG_3181.PNG','imagen','Captura de pantalla de una conversación de la aplicación de mensajería WhatsApp. La interfaz muestra un chat entre el usuario titular (el padre) y un contacto guardado como ''IO''. El diálogo refleja una interacción cotidiana de apoyo escolar donde la menor solicita ayuda para adquirir un instrumento musical.',replace('17:54\n[Icono de contacto: gato blanco] IO\nmié 7 de jun\nGenial! 15:03 ✓✓\nLinda tarde 15:03 ✓✓\nPapá 17:46\nHola, hija 17:46 ✓✓\nNecesito una flauta 17:46\n.. : : : : : : : : ..\n. . " " %%%% % % : .\n. . . . : : %%%%%% :\n. . : : : : . . : : %%%%%% :\n: . . . . . . : : : %%%%%% : :\n. . . . . . . : %%%%%% : :\n. . . . . . . . : %%%%%% : :\n. : . . . . . . : : %%%%%% : :\n: : . . . . . . . % %%%%%% : :\n: : . . . . . . : % %%%%%% : :\n: : . . . . . . % % %%%%%% : :\n. . . . . . . . . % %%%%%% : :\n: . . . . . . . . % %%%%%% : :\n: . . . . . . . . % %%%%%% : :\n. . . . . . . . . . : : : : . . 17:46\nY la tuya? 17:46 ✓✓\nEsque se perdio y no la encuentro 17:46\nPero es para mañana 17:47\n(メ﹏メ) 17:47','\n',char(10)),'2023-06-07 17:47','sin_relevancia_procesal','Ninguna',5,'La evidencia digital demuestra una comunicación fluida y un vínculo afectivo vigente entre el padre y la menor. La adolescente recurre de forma espontánea al progenitor para resolver una necesidad escolar inmediata, lo que sugiere presencia y responsabilidad parental en el desarrollo educativo de la hija.','René Iván Anzorena Hernández (Padre), I.A.L. (Hija, identificada como ''IO'')','Artículo 414 Bis y 416 Ter del Código Civil para el Distrito Federal, referentes a los deberes de crianza y el derecho del menor a la convivencia con sus progenitores.','{"relacion_paterno_filial": "Muestra un patrón de comunicación asertiva y confianza, lo cual es relevante para desvirtuar posibles alegatos de abandono o alienación parental."}','APROBADO. Es una prueba de descargo fundamental para acreditar el cumplimiento de deberes de cuidado y la existencia de un lazo emocional sólido con la adolescente.','2026-04-03 01:03:31');
INSERT INTO hallazgos_proactivos VALUES(8,NULL,'8ed3a94f6a7495d23cd58938a7a8abe3ee2848950d450a67f0ab5c2916249e04','IMG_0312.PNG','2023/WhatsApp iMessage/IMG_0312.PNG','imagen','Captura de pantalla de una conversación de WhatsApp en un dispositivo iPhone. Se observa un intercambio de mensajes entre el usuario (remitente, presuntamente René Iván Anzorena Hernández) y un contacto registrado como ''IO'' (identificada por el contexto como su hija menor de edad, I.A.L.). La interfaz muestra el modo oscuro y un botón de navegación hacia abajo indicando mensajes pendientes de lectura.',replace('IO: Por eso le dijiste a esos jueses (19:34)\nYo (respondiendo a ''IO: Yo quiero estar con Viry''): hija, depende de muchas cosas, algunas aún no son cosas que tomes tú en cuenta; por eso hay que esperar a las autoridades. (19:34, leído)\nIO: Que tiene? (19:35)\nIO: Que cosas (19:35)\nYo (respondiendo a ''IO: Por eso le dijiste a esos jueses''): Hija, con el juez se va a hablar hasta abril. Ni tu mamá ni yo hemos hablado con el juez. En este momento tu mamá dió su punto de vista y yo el mío. Apenas en abril el juez nos va a recibir y va a escuchar los puntos de vista de cada quién (19:3x)','\n',char(10)),'2023-01-24 19:51','alienacion_parental, violencia_vicaria','Violencia Psicoemocional',8,'El intercambio evidencia que la menor de edad está siendo informada de manera sesgada sobre las actuaciones procesales del padre, utilizándola como interlocutora del conflicto judicial. El padre intenta desmitificar las percepciones de la hija, quien lo confronta por supuestas declaraciones ante ''los jueces'', lo cual es un indicador de manipulación parental externa.','René Iván Anzorena Hernández, I.A.L. (Menor), Viridiana López Valenzuela (mencionada como ''Viry'' y ''mamá'')','Artículos 416 Ter y 417 Bis del Código Civil para el Distrito Federal; Artículo 103 de la Ley General de los Derechos de Niñas, Niños y Adolescentes.','{"hecho_relacionado": "Influencia externa en la voluntad de la menor respecto a la guarda y custodia.", "evidencia_previa": "Coincide con alegatos de manipulación de la conciencia de la menor por parte de la madre."}','APROBADO. Es una prueba sustancial de cómo la menor está siendo involucrada indebidamente en el proceso legal, afectando su estabilidad psicoemocional y el vínculo paterno-filial.','2026-04-03 01:04:46');
INSERT INTO hallazgos_proactivos VALUES(9,NULL,'641782acedeb1c935d02d326a4aca728b8b41d5cd0e4079f76e2e427989bb2d2','IMG_3076.PNG','2023/WhatsApp iMessage/IMG_3076.PNG','imagen','Captura de pantalla de una conversación de WhatsApp en un dispositivo móvil con sistema operativo iOS. Se observa un chat entre ''Viridiana Lopez'' y el usuario del teléfono (presuntamente el actor). La conversación muestra una disputa logística sobre el traslado de la menor y comentarios hostiles de carácter personal.','17:45 ... Viridiana Lopez últ. vez 09/06/23 15:52 ... Viridiana Lopez jun yo voy con mi familia a comer [Mensaje citado] ... Para eso e irte a la fiesta si tienes gasolina? 14:12 √√ ... Viridiana Lopez: me la llevas a temprano o me la llevas a impulsora? 14:12 ... Tú: Pero no para venir por ella a la escuela? 14:12 √√ ... Tú Para eso e irte a la fiesta si tienes gasolina? [Mensaje citado] ... Viridiana Lopez: No es asunto tuyo 14:12 ... Viridiana Lopez me la llevas a temprano o me la llevas a impulsora? [Mensaje citado] ... Tú: La puedo llevar al departamento a las 21:00 14:12 √√ ... Tú La puedo llevar al departamento a las 21:00 [Mensaje citado] ... Viridiana Lopez: Me voy a las 5 o o me la llevas con mi familia 14:13','2023-06-09 14:13','desacato_visitas, violencia_vicaria','Violencia Psicoemocional y Vicaria',7,'Intercambio de mensajes que evidencia la imposición unilateral de horarios por parte de la demandada (''Me voy a las 5''), ignorando la propuesta de convivencia del padre. Se observa un tono hostil y de control sobre las actividades personales del actor (''si tienes gasolina''), utilizando la logística de la menor como mecanismo de presión.','Viridiana López Valenzuela, René Iván Anzorena Hernández (identificado como ''Tú''), I.A.L. (referida como ''la'')','Código Civil para el Distrito Federal, Artículos 416 Ter (derecho de convivencia) y 417 (obstaculización); Ley de Acceso de las Mujeres a una Vida Libre de Violencia (en el contexto de violencia vicaria y control psicoemocional).','{"logistica_escolar": "Se menciona la escuela como punto de conflicto en la recolección.", "obstruccion": "La demandada condiciona la entrega a su conveniencia personal/familiar inmediata."}','APROBADO. Sirve como indicio de la actitud obstructiva de la custodia y el ejercicio de violencia psicoemocional mediante el control de la movilidad del padre.','2026-04-03 01:05:39');
INSERT INTO hallazgos_proactivos VALUES(10,NULL,'b7c0c9eac8372e2060666cc304dc40de841775a9f224c1dae8397ad1aa72a27b','IMG_3112.PNG','2023/WhatsApp iMessage/IMG_3112.PNG','imagen','Captura de pantalla de la aplicación de mensajería WhatsApp que muestra una conversación entre el usuario del dispositivo (padre) y un contacto guardado como ''IO'' (hija). La interfaz presenta un modo oscuro, la hora del sistema 17:49 y la batería cargando. El intercambio de mensajes refleja una solicitud cotidiana de compra de suministros.',replace('En tamaño completo de la hoja o mitad de hoja? 19:38 (Leído)\nCompleta 19:44\nOk 19:45 (Leído)\nmar 25 de abr\nPapá me puedes comprar unos cubrebocas ahí en Winos? 6:47\n[Sticker de personaje con taza de café] 6:47\nHola, hija 6:47 (Leído)\nWinos abre de pies de las 07:00. Si está abierto te los compro 6:47 (Leído)\nOk 6:48','\n',char(10)),'2023-04-25 06:48','sin_relevancia_procesal','Ninguna',4,'Conversación de WhatsApp que demuestra una comunicación fluida y sana entre el padre y la menor. La menor solicita la compra de insumos de higiene (cubrebocas) y el padre responde con disposición inmediata de cuidado. El archivo sirve como prueba de descargo contra posibles acusaciones de abandono o falta de comunicación.','René Iván Anzorena Hernández (Padre), I.A.L. (Hija, identificada como IO)','Artículo 416 Ter del Código Civil para la Ciudad de México (sobre el derecho de convivencia y el interés superior de la infancia).','{"vinculo_afectivo": "Demuestra la existencia de un canal de comunicación directo y respetuoso entre padre e hija sin intermediarios."}','APROBADO si se utiliza para acreditar el cumplimiento de deberes de asistencia y la existencia de un vínculo afectivo sólido que desvirtúe acusaciones de alienación parental o abandono.','2026-04-03 01:07:29');
INSERT INTO hallazgos_proactivos VALUES(11,NULL,'14a3c70f04767e27562b5bbacb6bc55a1fe6290bf0a20cd80df84710c0d4645a','Captura de pantalla 2026-02-26 a la(s) 13.09.16.png','2023/WhatsApp iMessage/Captura de pantalla 2026-02-26 a la(s) 13.09.16.png','imagen','Captura de pantalla de una conversación de iMessage entre René Iván Anzorena Hernández (emisor, burbujas verdes) y Viridiana Lopez (receptora, burbujas grises). El diálogo versa sobre la logística de traslado y entrega de una menor de edad identificada como ''IO'' (I.A.L.). Se observa una coordinación de horarios y ubicación para el régimen de visitas o convivencia.',replace('Para: Viridiana Lopez\n+52 55 7224 7939\nEnviar correo electrónico\nMostrar tarjeta de contacto\n[René]: Ok, con cuidado\n[René]: Aquí las Espero\n[René]: Hola, En cuánto tiempo Llegan\n[Viridiana]: Estamos en Tlatelolco\n[René]: Les mando Didi Mándame ubi Quiero que lleguen Bien\n[Viridiana]: Estamos en insurgentes\n[René]: Te mando didi ? O como vienen ?\n[Viridiana]: En carro\n[René]: En carro, ok Donde llegan, están bien? Aquí los recibo\n[Viridiana]: Si, todo bien Llegamos a la oficina\n[René]: Carro, color? Vamos bajando\n[Viridiana]: Aun faltan 3 semaforo\n[René]: ✨✨\n17 sep 2023, 17:26\n[René]: Buena tarde, Viridiana. IO está en el departamento a las 19:00 Por favor recíbela en la entrada del edificio Gracias\n[Viridiana]: Gracias René, por favor 7:30 para evitar dejarlos esperando. Buena tarde\n[René]: Me insististe que a las 19:00 para evitar problemas. Por favor ni un minuto después de 19:30. No puedo esperar por pendientes personales.\n17 sep 2023, 19:02\n[Viridiana]: Yo estoy aqui desde las 6:30, ofreci ese tiempo para evitar retraso por alguna eventualidad o trafico, en el momento que gustes René. Buena noche.','\n',char(10)),'2023-09-17 19:02','desacato_visitas','Ninguna',7,'El archivo documenta la logística de entrega de la menor I.A.L. el 17 de septiembre de 2023, evidenciando una comunicación rígida respecto a la puntualidad. La madre (demandada) afirma haber llegado con antelación (18:30 hrs) para cumplir con la entrega pactada a las 19:00 hrs, mientras el padre (actor) establece un límite estricto de tolerancia de 30 minutos alegando asuntos personales.','René Iván Anzorena Hernández, Viridiana López Valenzuela, I.A.L. (referida como IO)','Código Civil para el Distrito Federal, Artículo 416, relativo al régimen de convivencias y el cumplimiento de horarios pactados para salvaguardar el interés superior de la niñez.','{"evento": "Entrega/recepción de la menor", "ubicaciones_mencionadas": ["Tlatelolco", "Insurgentes", "La oficina", "Entrada del edificio"]}','APROBADO si construye sustento legal para CDMX 2026, ya que permite fiscalizar el cumplimiento o la obstrucción del régimen de visitas y la actitud de los progenitores ante los horarios judiciales o acordados.','2026-04-03 01:09:52');
INSERT INTO hallazgos_proactivos VALUES(12,NULL,'ad9f3d7dd6f70380fa3574cb6a73f4675c1997c5cf3af7208585f794b0bfae0a','IMG_3170.PNG','2023/WhatsApp iMessage/IMG_3170.PNG','imagen','Captura de pantalla de una conversación de WhatsApp en un dispositivo móvil con sistema operativo iOS. Se observa un hilo de mensajes entre el remitente (identificado por el contexto como el padre) y un contacto guardado como ''IO'' (la hija, I.A.L.). La conversación abarca tres días y trata sobre la entrega de comida (pizza), el encuentro en la escuela y la confirmación de envío de dinero para gastos a través de la madre.',replace('17:53 [icono señal] [icono wifi] [icono batería/carga]\n< [flecha atrás] [foto perfil gato] IO [icono video] [icono teléfono]\nSi 17:38\nmié 31 de may\nYa estan abajo 17:38 [doble check azul]\nHay que bajar por la pizza 17:38 [doble check azul]\nGracias 17:38\nPasa buena noche, hija 21:11 [doble check azul]\nDescansa y te veo mañana temprano en la escuela 21:11 [doble check azul]\njue 1 de jun\nHola hija. 14:34 [doble check azul]\nvie 2 de jun\nHola , hija.\nYa le mandé a tu mamá el dinero para tus gastos.\nPorfa acuerda con ella lo que necesites para ti 18:09 [doble check azul]\n[botón flecha abajo circular]','\n',char(10)),'2023-06-02 18:09','sin_relevancia_procesal','Ninguna',7,'La evidencia muestra una interacción parental funcional y proactiva por parte del padre. Se acredita el cumplimiento de obligaciones alimentarias (mención de envío de dinero para gastos), involucramiento en la vida académica (referencia a verse en la escuela) y procuración de bienestar cotidiano.','René Iván Anzorena Hernández (Padre/Emisor), I.A.L. (Hija/Receptora ''IO''), Viridiana López Valenzuela (Mencionada como ''mamá'')','Artículos 411 y 417 del Código Civil para el Distrito Federal, relativos al cumplimiento de las obligaciones de crianza y el derecho de convivencia, así como el principio de Interés Superior de la Niñez.','{"interacción_educativa": "El mensaje del 31 de mayo confirma la presencia física del padre en el entorno escolar de la menor.", "cumplimiento_económico": "El mensaje del 2 de junio vincula al padre con la provisión de recursos económicos entregados a través de la custodia."}','APROBADO si construye sustento legal para CDMX 2026. Justifica: Esta prueba es fundamental para desvirtuar posibles acusaciones de abandono económico o falta de interés afectivo-educativo por parte del padre.','2026-04-03 01:10:59');
INSERT INTO hallazgos_proactivos VALUES(13,NULL,'288676a5adcb5b5644be695c1260237b857b198ece0a5ce49e1208378358ff7e','IMG_0318.PNG','2023/WhatsApp iMessage/IMG_0318.PNG','imagen','Captura de pantalla de una conversación de WhatsApp en un iPhone. El chat es entre el usuario del teléfono (presumiblemente el padre, René Iván Anzorena Hernández) y un contacto registrado como ''IO'' (identificada como la menor I.A.L.). La conversación muestra una tensión emocional alta, donde la menor manifiesta rechazo hacia el padre y menciona a ''Viry'' (Viridiana López Valenzuela) como una figura protectora frente a él.',replace('19:52\n1 [Imagen de perfil: gato anime] IO [Iconos de cámara y teléfono]\n[Mensaje citado de IO: Viry me cuida de que no me obliges]\nmira hija, es tu manera de ver las cosas ahora y lo respeto; pero no estoy de acuerdo 19:46 [leído]\ncuando Viry no estaba me obligabas 19:47\n[Mensaje citado de IO: Audio 0:04]\nhija, solo hay estática.\nSi prefieres nos vemos o llamamos por teléfono para escuchar bien lo que tienes que decir 19:47 [leído]\n🚫 Se eliminó este mensaje. 19:47\nEntonces estoy mal y tú bien? 19:47\nno, solamente pensamos diferente pero si quieres lo hablamos en persona, por teléfono 19:48 [leído]\nNo 19:48\nNo me gusta hablar contigo','\n',char(10)),'2023-01-24 19:52','alienacion_parental, violencia_vicaria','Violencia Psicoemocional, Violencia Vicaria',8,'La evidencia digital revela una fractura significativa en el vínculo paterno-filial, donde la menor de 15 años manifiesta un discurso de rechazo y victimización frente al padre, posicionando a la madre como única figura de protección. Se observa una resistencia absoluta de la adolescente a la comunicación verbal o presencial, comportamiento característico de la alienación parental inducida. El texto sugiere que la menor ha adoptado una narrativa de conflicto que beneficia la postura de la madre custodia.','René Iván Anzorena Hernández, I.A.L. (menor, identificada como ''IO''), Viridiana López Valenzuela (mencionada como ''Viry'')','Código Civil para el Distrito Federal, Artículo 444 Bis (Alienación Parental); Ley General de los Derechos de Niñas, Niños y Adolescentes, Artículos 13 y 103 (Derecho a la convivencia y protección contra la manipulación).','{"interlocutor_madre": "La referencia a ''Viry'' como protectora valida la hipótesis de triangulación donde la madre interfiere en la percepción de la hija sobre el padre.", "estado_comunicacion": "La negativa explícita a hablar (''No me gusta hablar contigo'') constituye una barrera para el régimen de visitas."}','APROBADO. Esta prueba es fundamental para acreditar el daño al vínculo afectivo y la posible inducción de rechazo (alienación parental), elementos críticos en la causal de pérdida de patria potestad en la CDMX.','2026-04-03 01:12:25');
INSERT INTO hallazgos_proactivos VALUES(14,NULL,'2ff55c9d320ff8eac5d6f439dd173d1a8e990664b4959e11d1fa7222924c8e73','IMG_3077.PNG','2023/WhatsApp iMessage/IMG_3077.PNG','imagen','Captura de pantalla de una conversación de WhatsApp en un dispositivo móvil. Se observa un intercambio de mensajes entre ''Viridiana Lopez'' y el usuario del dispositivo (René Iván Anzorena Hernández). El diálogo gira en torno a la logística de entrega y recolección de su hija (I.A.L.), evidenciando conflictos sobre el cumplimiento de un acuerdo judicial previo respecto al lugar y horario de las visitas.',replace('[Viridiana Lopez]: La puedo llevar al d... a las 21:00\n[vie 16 de jun]\n[Viridiana Lopez] 14:13: Me voy a las 5 o o me la llevas con mi familia\n[René Iván Anzorena Hernández] 14:13 (Respuesta a mensaje de Viridiana): Ven por ella a la escuela a las 14:30 que es su hura de salida o la puedo llevar a las 21:00 a su domicilio en Boleo\n[Viridiana Lopez] 14:14: Voy por ella y mañana pasas con mi familia al estado de mexico\n[Viridiana Lopez] 14:14: por ella a las 11\n[René Iván Anzorena Hernández] 14:14: En el acuerdo con el juez establece qué pasó por ella a su domicilio\n[Viridiana Lopez] 14:14: y solo sábado y domingo y te la llevas sin mi consentimiento\n[Viridiana Lopez] 14:15: entre semana\n[René Iván Anzorena Hernández] (mensaje incompleto): cuando te desapareces por días no','\n',char(10)),'2023-06-16 14:15','desacato_visitas, violencia_vicaria','Violencia Psicoemocional, Violencia Vicaria',8,'La evidencia muestra una resistencia explícita de la demandada a cumplir con los términos del convenio judicial respecto al domicilio de entrega de la menor. Se observa una conducta impositiva que busca alterar el régimen de visitas pactado, utilizando el traslado de la menor al Estado de México como mecanismo de presión. La mención final sobre ausencias de la madre por varios días sugiere una posible negligencia en el cuidado constante.','Viridiana López Valenzuela, René Iván Anzorena Hernández, I.A.L. (referida como ''ella'')','Artículos 416 Ter y 417 del Código Civil para el Distrito Federal (incumplimiento del régimen de convivencias) y Ley General de Acceso de las Mujeres a una Vida Libre de Violencia (Violencia Vicaria por el uso de la hija para condicionar al progenitor).','{"acuerdo_judicial": "Referencia directa a un convenio establecido ante juez familiar que no está siendo respetado por la demandada.", "riesgo_sustraccion": "La mención de trasladar a la menor al Estado de México fuera del acuerdo pactado representa un riesgo potencial de obstrucción de visitas."}','APROBADO. El documento constituye prueba documental directa del desacato a órdenes judiciales y de la manipulación del régimen de convivencia por parte de la custodia.','2026-04-03 01:15:22');
INSERT INTO hallazgos_proactivos VALUES(15,NULL,'5ad0e43146354fecebe4630db43036406118261a69a5ba8997c6e313b2fb135c','IMG_3075.PNG','2023/WhatsApp iMessage/IMG_3075.PNG','imagen','Captura de pantalla de un dispositivo móvil mostrando una conversación de la aplicación WhatsApp. Se observa un intercambio de mensajes entre el remitente (presuntamente René Iván Anzorena Hernández) y el contacto ''Viridiana Lopez''. La conversación gira en torno a la logística de recolección y entrega de una menor (''ella''), mencionando específicamente horarios escolares, comidas y el cumplimiento de acuerdos ante un juez.',replace('[Encabezado]: Viridiana Lopez, últ. vez 09/06/23 15:52. [Cuerpo del chat]:\nActor (14:07): Pasa hoy a la escuela s la hora que debes pasar.\nActor (14:07): Si ella quiere comer conmigo yo con gusto como con ella y la llevo al departamento después.\nActor (14:08): Mañana paso por ella a donde se declaró como vivienda ante el juez.\nViridiana Lopez (14:08): me la traes al departamento\nActor (14:08): [Citando ''me la traes al departamento''] Tengo trabajo, la puedo llevar hasta las 21:00\nViridiana Lopez (14:08): ok\nViridiana Lopez (14:11): Y nuevamente no cambies versiones a tu conveniencia\nViridiana Lopez (14:12): yo voy con mi familia a comer\n[Campo de entrada de texto citando a Viridiana Lopez]: yo voy con mi familia a comer','\n',char(10)),'2023-06-16 17:45','desacato_visitas, violencia_vicaria','Violencia Psicoemocional, Violencia Vicaria',7,'La evidencia muestra al Actor intentando ceñirse a las disposiciones judiciales sobre el domicilio de convivencia, mientras la Demandada impone lugares de entrega distintos (''departamento'') y utiliza un lenguaje confrontativo para descalificar al padre (''no cambies versiones a tu conveniencia''). Se observa una dinámica donde la logística de la menor está supeditada a las demandas unilaterales de la madre, ignorando lo declarado ante el juez.','Viridiana López Valenzuela, René Iván Anzorena Hernández, I.A.L. (referenciada implícitamente)','Código Civil para el Distrito Federal, Artículo 416 (Derecho de convivencia) y Artículo 444 Bis (Suspensión por alienación o violencia). Ley General de Acceso de las Mujeres a una Vida Libre de Violencia (en lo relativo a Violencia Vicaria).','{"contexto": "Se relaciona con el expediente 1784/2022, específicamente con la resistencia de la madre a respetar los domicilios declarados judicialmente para las entregas de la menor."}','APROBADO. Documenta la disposición de cumplimiento del padre y la actitud obstructiva/manipuladora de la madre respecto al régimen de visitas y acuerdos judiciales.','2026-04-03 01:16:07');
INSERT INTO hallazgos_proactivos VALUES(16,NULL,'93956a06876a68e48e8aeee95baedae4dc36232d0a688b959149babe41e54506','IMG_3138.PNG','2023/WhatsApp iMessage/IMG_3138.PNG','imagen','Captura de pantalla de una conversación de la aplicación WhatsApp entre el actor (padre) y la menor identificada como ''IO'' (I.A.L.). La imagen muestra una transferencia bancaria exitosa de BBVA y un diálogo posterior sobre el consumo de alimentos.',replace('17:51 ... IO [Cámara] [Teléfono]\nlun 15 de may\n$100.00\nEsta transferencia no genera comisión\nCu Ca\nCuenta Cachorrito\n*8596 *5016\nConcepto Lunch\nFolio: 3139007835\nBBVA\nHija, hoy no te vi en l mañana así que te paso a tu tarjeta lo del lunch del día. 11:30 [Visto]\nHola, hija. Pudiste comprar tu birria? Te llevó tu mamá? 15:11 [Visto]\nNo 15:37\nDice que no debemos salirnos del presupuesto 15:37\nTú: [Foto de la transferencia] Hija, hoy no te vi en l mañana así que te paso a tu tarjeta lo del lunch del día.','\n',char(10)),'2023-05-15 15:37','violencia_vicaria, alienacion_parental','Violencia Económica, Violencia Psicoemocional',7,'La evidencia digital demuestra que el actor cumple con sus obligaciones alimentarias extraordinarias mediante transferencias directas a la menor. La respuesta de la adolescente sugiere que la demandada ejerce un control restrictivo sobre los recursos proporcionados por el padre, interfiriendo en el bienestar y autonomía de la hija. Este comportamiento se alinea con tácticas de control que buscan minimizar el rol del padre como proveedor.','René Iván Anzorena Hernández (Padre/Emisor), I.A.L. (Hija/Receptora identificada como ''IO''), Viridiana López Valenzuela (Mencionada como ''mamá'')','Artículo 416 Bis y 444 Bis del Código Civil para el Distrito Federal; Artículo 3, fracción IV de la Ley de los Derechos de Niñas, Niños y Adolescentes de la CDMX.','{"hecho_relacionado": "Cumplimiento de pensión alimentaria y obstrucción de beneficios parentales por parte de la custodia.", "contexto": "La menor de 15 años reporta una restricción impuesta por la madre que anula la acción de cuidado/sustento del padre."}','APROBADO. Es relevante para demostrar que el padre mantiene una actitud diligente de proveeduría y que la madre obstaculiza el disfrute de dichos beneficios, afectando el interés superior de la menor.','2026-04-03 04:17:02');
INSERT INTO hallazgos_proactivos VALUES(17,NULL,'b1e43cef235e45ab825c56004b35cc80cf358607ce864ce61eee19b50a6b0686','ANZORENA LOPEZ IO 1er parcial.pdf','Documentos IO/IO UVM/CALIFICACIONES/ANZORENA LOPEZ IO 1er parcial.pdf','documento','Documento digital consistente en un ''Informe de Desempeño Académico'' emitido por la Universidad del Valle de México (UVM), Campus San Rafael, correspondiente al primer parcial del programa Preparatoria UNAM. El reporte detalla las calificaciones y asistencias de la menor I.A.L. (Anzorena Lopez Io), identificando al padre, René Iván Anzorena Hernández, como destinatario y tutor. El documento muestra un rendimiento escolar crítico con múltiples materias reprobadas.','UNIVERSIDAD DEL VALLE DE MEXICO. CAMPUS SAN RAFAEL. INFORME DE DESEMPEÑO ACADEMICO. FECHA: 21-11-2025. HORA: 12:05. DESTINATARIO NOMBRE DEL PADRE O TUTOR: RENE IVAN ANZORENA HERNANDEZ. NOMBRE DEL ESTUDIANTE: ANZORENA LOPEZ IO. PROGRAMA ACADEMICO: PREPARATORIA UNAM. CRN NOMBRE DE LA MATERIA: 142 GENERO Y PREVENC D L VIOLENCIA 10.00; 167 DIBUJO II 0.01; 313 LOGICA 3.59; 513 LENGUA ESPAÑOLA 6.77; 383 FISICA III 3.11; 261 ORIENTACION EDUCATIVA IV 7.60; 289 EDUCACION FISICA IV 7.80; 325 VALORES ETICOS I 10.00; 116 INFORMATICA 5.25; 556 MATEMATICAS IV 5.80; 228 HISTORIA UNIVERSAL III 3.80; 424 GEOGRAFIA 5.00; 469 INGLES IV 6.30; 651 EDUC ESTETICA Y ARTISTICA IV 5.80. PROMEDIOS Y TOTALES DEL SEMESTRE: 5.77. NOTA: La Calificación Mínima Aprobatoria es de: 6.','2025-11-21 12:05','inaccion_educativa','Ninguna',9,'El informe académico revela una situación de negligencia en la supervisión escolar de la menor por parte de la madre custodia, evidenciando que 8 de las 14 materias están reprobadas, con casos extremos como 0.01 en Dibujo II y 3.11 en Física III. El promedio general de 5.77 se encuentra por debajo del mínimo aprobatorio, lo que constituye una prueba documental del descuido en los deberes de formación y educación. La recurrencia de inasistencias en diversas materias refuerza la hipótesis de abandono de seguimiento académico.','RENE IVAN ANZORENA HERNANDEZ, ANZORENA LOPEZ IO','Artículos 411, 414 Bis y 444 Fracción IV del Código Civil para la CDMX; Artículo 57 de la Ley General de los Derechos de Niñas, Niños y Adolescentes (LGDNNA).','{"hecho_principal": "Inacción educativa por parte de la demandada Viridiana López Valenzuela al ostentar la custodia física de la menor.", "patron_secundario": "Posible ocultamiento de la situación escolar al padre, quien figura como destinatario de un informe que refleja una crisis académica inminente."}','APROBADO si construye sustento legal para CDMX 2026, ya que el bajo rendimiento académico y el ausentismo escolar son causales directas para cuestionar la idoneidad de la guardia y custodia en términos de protección del interés superior de la infancia.','2026-04-03 18:37:45');
INSERT INTO hallazgos_proactivos VALUES(18,NULL,'ee0f7a7ca3e33b4f6164486b39f181f7f7c34f119da0f520f7ceda244dd80baa','010223648 IO ANZORENA.pdf','Documentos IO/IO UVM/PAGOS/010223648 IO ANZORENA.pdf','documento','Documento digital consistente en un comprobante de pago de servicios educativos emitido por la Universidad del Valle de México (UVM) a nombre de la beneficiaria IO Anzorena López. El documento detalla el pago de la colegiatura parcialidad 5 y un cargo por pago extemporáneo.','UNIVERSIDAD DEL VALLE DE MEXICO. R.F.C. UVM870210LT1. SADI CARNOT 57, COL. SAN RAFAEL, CUAUHTEMOC, CIUDAD DE MEXICO, C. P. 06470. NO. CONTROL: 3310043. FECHA DE EMISIÓN: 08/01/2026 00:00. CAJERO: TIBCO01. NO. DE CUENTA: 010223648. BENEFICIARIO: IO ANZORENA LOPEZ. R. F. C: AOLl101222MMC. CLAVE: B205 DESCRIPCIÓN: COLEGIATURA/PARC 5 PU PROG: PUNM01U25 CICLO: 202505 IMPORTE: 5,090.00. CLAVE: RX05 DESCRIPCIÓN: CARGO EXTEMP PARC 5 PROG: PUNM01U25 CICLO: 202505 IMPORTE: 203.00. TOTAL DE PAGOS: 2. SUB-TOTAL: 5,265.00. IVA: 28.00. TOTAL: 5,293.00. CINCO MIL DOSCIENTOS NOVENTA Y TRES PESOS 00/100 M.N. Comprobante no válido para efectos Fiscales.','2026-01-08 00:00','sin_relevancia_procesal','Ninguna',7,'Comprobante de pago escolar que acredita la inscripción y vigencia académica de la menor I.A.L. en la Universidad del Valle de México para el ciclo 202505. El documento registra un cargo por pago extemporáneo, lo que sugiere un retraso en la gestión administrativa de las colegiaturas.','IO Anzorena López','Artículos 301, 303 y 308 del Código Civil para el Distrito Federal (relativos a la obligación alimentaria que comprende la educación y formación para el trabajo).','{"expediente": "1784/2022", "estatus_escolar": "Acredita que la menor continúa su formación académica bajo el programa PUNM01U25."}','APROBADO si construye sustento legal para acreditar el cumplimiento de obligaciones alimentarias y el estado educativo de la menor en el año 2026.','2026-04-03 18:48:31');
INSERT INTO hallazgos_proactivos VALUES(19,NULL,'3b6f46f031496c3438afc6a7880e6598cc3167101c1262de9f72c1a80a77fecd','202279115521961ComprobanteAsignacion-AOLI101222MMCNPXA0.pdf.pdf','Documentos IO/202279115521961ComprobanteAsignacion-AOLI101222MMCNPXA0.pdf.pdf','documento','Documento oficial en formato digital (PDF) emitido por la Autoridad Educativa Federal en la Ciudad de México (AEFCM). Se trata de un ''Comprobante de Asignación a Secundaria'' del Sistema Anticipado de Inscripción y Distribución (SAID) para el ciclo escolar 2022-2023. El documento presenta logotipos de la Secretaría de Educación Pública (SEP) y contiene los datos de asignación de una menor de edad a un plantel público.','SISTEMA ANTICIPADO DE INSCRIPCIÓN Y DISTRIBUCIÓN (SAID). AUTORIDAD EDUCATIVA FEDERAL EN LA CIUDAD DE MÉXICO. SEC-ASI-10. DIRECCIÓN GENERAL DE PLANEACIÓN, PROGRAMACIÓN Y EVALUACIÓN EDUCATIVA. COMPROBANTE DE ASIGNACIÓN A SECUNDARIA. LA SECRETARÍA DE EDUCACIÓN PÚBLICA INFORMA QUE EL NIÑO (A): ANZORENA LOPEZ IO. OP: 43. FOLIO: 203. CURP: AOLI101222MMCNPXA0. HA QUEDADO ASIGNADO PARA CURSAR EL PRIMER GRADO DE EDUCACIÓN SECUNDARIA EN EL CICLO ESCOLAR: 2022-2023. EN LA ESCUELA: ANTONIO BALLESTEROS USANO. CLAVE DEL PLANTEL: 09DES0106A. TURNO: TIEMPO COMPLETO SIN INGESTA. DOMICILIO DEL PLANTEL: CALLE MANUEL GONZÁLEZ 32, COLONIA UNIDAD NONOALCO TLATELOLCO, ALCALDÍA CUAUHTEMOC. Fecha de consulta: 2022/08/09 23:56. Firmas: Genaro Rey Meneses (Dirección de Planeación Educativa) y Yosany Olivier Moreno (Subdirección del SAID).','2022-08-09 23:56','sin_relevancia_procesal','Ninguna',5,'El documento es un comprobante oficial de asignación escolar que acredita que la menor I.A.L. fue inscrita para el primer grado de secundaria en el ciclo 2022-2023. Establece el cumplimiento inicial de la obligación educativa por parte de quien ostenta la custodia en esa fecha. Sirve como prueba de ubicación geográfica y estatus académico basal para contrastar con posibles omisiones posteriores.','ANZORENA LOPEZ IO, Genaro Rey Meneses, Yosany Olivier Moreno','Artículos 411, 414 y 416 del Código Civil para el Distrito Federal, relativos a la obligación de los padres de asegurar la educación de los hijos.','{"escolaridad": "Establece el plantel de adscripción inicial en la Alcaldía Cuauhtémoc, relevante para verificar si hubo cambios de domicilio no notificados o interrupción de estudios posteriores."}','APROBADO: Es una prueba documental pública que establece el punto de partida del seguimiento educativo de la menor, indispensable para demostrar o descartar el patrón de inacción educativa.','2026-04-03 18:51:00');
INSERT INTO hallazgos_proactivos VALUES(20,NULL,'3697a81a2df0d93558846cf956a0661cfeba0d58732b7507279fa323ffc86c86','PHOTO-2024-10-05-09-21-24.jpg','PAGOS PENSIÓN/PHOTO-2024-10-05-09-21-24.jpg','imagen','Imagen digital que muestra un comprobante de transferencia bancaria electrónica realizado a través de la aplicación móvil de BBVA. El documento detalla una operación exitosa de envío de fondos.',replace('BBVA\nJUSTIFICANTE DE LA OPERACIÓN\nGENERAL\nTipo de operación\nTransferencia a terceros BBVA\nNúmero de operación\n7108852297\nFecha\n05 octubre 2024\nHora\n09:20 h\nConcepto\npension IO octubre\nIMPORTE\nImporte transferido\n$ 6,000.00\nORIGEN\nCuenta de origen\n•8596\nDESTINO\nNombre del beneficiario\nVIRIDIANA LOPEZ VALENZUELA\nNombre del banco\nCuenta BBVA\nCuenta de destino\n•0117\nBBVA México, S.A., Institución de Banca Múltiple, Grupo Financiero BBVA México. Avenida Paseo de la Reforma 510, colonia Juárez, código postal 06600, alcaldía Cuauhtémoc, Ciudad de México.','\n',char(10)),'2024-10-05 09:20','sin_relevancia_procesal','Ninguna',8,'Se identifica un comprobante de transferencia bancaria por $6,000.00 MXN con fecha 5 de octubre de 2024 a favor de Viridiana López Valenzuela. El concepto de pago especifica ''pension IO octubre'', lo cual acredita el cumplimiento de la obligación alimentaria para con el menor involucrado en el periodo señalado.','VIRIDIANA LOPEZ VALENZUELA, René Iván Anzorena Hernández (emisor implícito), I.A.L. (referenciada en concepto ''IO'')','Artículos 301, 303 y 308 del Código Civil para el Distrito Federal (Ciudad de México).','{"hecho_relevante": "Cumplimiento de pensión alimenticia", "observacion": "Desvirtúa proactivamente cualquier acusación de abandono económico o incumplimiento de deberes alimentarios por parte del actor."}','APROBADO si construye sustento legal para CDMX 2026, ya que documenta la solvencia y cumplimiento del padre, neutralizando causales de pérdida de patria potestad por abandono.','2026-04-04 01:05:34');
INSERT INTO hallazgos_proactivos VALUES(21,NULL,'a4d6e3e3cc357b97ed9aee1c4277dc7280aae4ee9997dd0395f816cc06eb2531','PHOTO-2024-11-05-20-18-49.jpg','PAGOS PENSIÓN/PHOTO-2024-11-05-20-18-49.jpg','imagen','Captura de pantalla de un comprobante digital de operación bancaria emitido por la institución BBVA México. El documento certifica un cargo exitoso realizado mediante banca electrónica, correspondiente al pago de una pensión alimenticia.',replace('BBVA\nCOMPROBANTE DE LA OPERACIÓN\nGENERAL\nTipo de operación\nCargo\nMotivo de pago\npension IO noviemb\nFecha de operación\n5 noviembre 2024, 20:09:00 h\nFecha de aplicación\n5 noviembre 2024, 00:00:00 h\nFolio de operación\n9826163772\nIMPORTE\nImporte\n$ -6,000.00\nORIGEN\nCuenta origen\n•8596','\n',char(10)),'2024-11-05 20:09','sin_relevancia_procesal','Ninguna',8,'El documento acredita el cumplimiento de la obligación económica por concepto de pensión alimenticia correspondiente a noviembre de 2024 por un monto de $6,000.00 MXN. Esta evidencia es fundamental para demostrar la responsabilidad del progenitor y desvirtuar cualquier narrativa de abandono económico. La referencia ''IO'' en el motivo coincide con las siglas de la menor involucrada en el litigio.','I.A.L. (identificada por las siglas IO en el motivo de pago)','Artículos 303 y 308 del Código Civil para el Distrito Federal, relativos a la obligación irrenunciable de proporcionar alimentos.','{"pago_mensual": "Noviembre 2024", "monto_fijo": "$6,000.00", "cuenta_origen": "Terminación 8596"}','APROBADO si construye sustento legal para CDMX 2026. Es una prueba de descargo crítica que valida el cumplimiento de deberes parentales, previniendo falsas acusaciones de incumplimiento alimentario.','2026-04-04 01:08:03');
INSERT INTO hallazgos_proactivos VALUES(22,NULL,'dace800e2f0aaaa6968c55d03ec9d80845cd271c1b5b68636e8cb7bd523c95e6','PHOTO-2025-11-04-18-07-56.jpg','PAGOS PENSIÓN/PHOTO-2025-11-04-18-07-56.jpg','imagen','Comprobante digital de operación bancaria emitido por la institución BBVA, que registra una transferencia electrónica de fondos realizada exitosamente hacia la cuenta de la demandada Viridiana López Valenzuela.',replace('BBVA\nCOMPROBANTE DE LA OPERACION\nTipo de operación\nTransferencia a terceros\nFolio de la operación\n0043665528\nFecha\n04 noviembre 2025\nHora\n18:07 h\nConcepto\nPension IO Noviembre\nImporte transferido\n$ 6,000.00\nCuenta de origen\n•8596\nNombre del beneficiario\nVIRIDIANA LOPEZ VALENZUELA\nNombre del banco\nCuenta BBVA\nCuenta de destino\n•0117\nBBVA México, S.A., Institución de Banca Múltiple, Grupo Financiero BBVA México. Avenida Paseo de la Reforma 510, colonia Juárez, código postal 06600, alcaldía Cuauhtémoc, Ciudad de México.','\n',char(10)),'2025-11-04 18:07','sin_relevancia_procesal','Ninguna',8,'Se acredita fehacientemente el pago de pensión alimenticia por un monto de $6,000.00 MXN correspondiente al mes de noviembre de 2025. El documento confirma el cumplimiento de las obligaciones económicas del progenitor no custodio hacia la beneficiaria Viridiana López Valenzuela. Esta evidencia es fundamental para desvirtuar cualquier imputación de abandono económico o incumplimiento de deberes alimentarios.','Viridiana López Valenzuela','Artículos 301, 303 y 308 del Código Civil para el Distrito Federal (CDMX), relativos a la reciprocidad y cumplimiento de la obligación alimentaria.','{"obligacion_alimentaria": "Evidencia directa de cumplimiento puntual del rubro de alimentos para el menor I.A.L."}','APROBADO: Documenta el cumplimiento de obligaciones de manutención, lo cual es un elemento de defensa crítico frente a una demanda de pérdida de patria potestad por presunto abandono.','2026-04-04 01:10:42');
INSERT INTO hallazgos_proactivos VALUES(23,NULL,'087900074e14a7347f50af78ab5bec235bcb655e2c8f2629ee9ba24736e1f402','0-1.png','Documentos IO/IO UVM/PAGOS/0-1.png','imagen','Imagen de un comprobante de pago o estado de cuenta de la Universidad del Valle de México (UVM) emitido a nombre de IO Anzorena Lopez. El documento detalla diversos cargos académicos, incluyendo colegiaturas y seguros, correspondientes al ciclo escolar 2025-05.',replace('UNIVERSIDAD DEL VALLE DE MEXICO\nUNIVERSIDAD DEL VALLE DE MEXICO\nR.F.C. UVM870210LT1 DSB\nSADI CARNOT 57, COL. SAN RAFAEL, CUAUHTEMOC, CIUDAD DE MEXICO, C. P. 06470 TEL.\nNO. CONTROL: 3336779\nFECHA DE EMISIÓN: 02/03/2026 00:00\nCAJERO: TIBCO01\nDatos del Beneficiario\nNO. DE CUENTA: 010223648\nBENEFICIARIO: IO ANZORENA LOPEZ\nR. F. C: AOLI101222MMC\nCLAVE DESCRIPCIÓN PROGRAMA-CICLO IMPORTE\nB207 COLEGIATURA/PARC 7 PU PROG: PUNM01U25 CICLO: 202505 1,133.00\nINCL INCORP ALUMNOS U.N.A.M. PROG: PUNM01U25 CICLO: 202505 656.00\nSDDL FUTURO SEGURO PROG: PUNM01U25 CICLO: 202505 665.00\nSGML SEG. GASTOS MEDICOS MAYORES PROG: PUNM01U25 CICLO: 202505 1,115.00\nSPPL PLAN DE PROTECCION ESCOLAR PROG: PUNM01U25 CICLO: 202505 1,115.00\nRX06 CARGO EXTEMP PARC 6 PROG: PUNM01U25 CICLO: 202505 609.00\nTOTAL DE PAGOS: 6\nSUB-TOTAL: 5,209.00\nIVA: 84.00\nTOTAL: 5,293.00\nCINCO MIL DOSCIENTOS NOVENTA Y TRES PESOS 00/100 M.N.\n"Comprobante no válido para efectos Fiscales"','\n',char(10)),'2026-03-02 00:00','sin_relevancia_procesal','Ninguna',8,'El documento acredita la inscripción vigente de la menor I.A.L. en la UVM y los costos asociados a su educación y salud (seguro de gastos médicos). Se observa un cargo por pago extemporáneo (RX06), lo que podría indicar irregularidades en la administración de los pagos escolares.','IO Anzorena Lopez','Artículos 301, 303 y 414 Bis del Código Civil para el Distrito Federal relativos a la obligación de proporcionar alimentos, que comprenden educación y salud.','{"escolaridad": "Confirma el nivel educativo y la institución donde la menor cursa sus estudios en 2026.", "salud": "Vincula la existencia de un seguro de gastos médicos mayores vigente para la menor."}','APROBADO si se utiliza para demostrar el cumplimiento o incumplimiento de la pensión alimenticia y el estado de la supervisión educativa de la menor.','2026-04-04 01:13:16');
INSERT INTO hallazgos_proactivos VALUES(24,266,'7aff9d151f33256ad5f108c2a54b2ad283603644353e8db02567b8be5bbb6b3a','PHOTO-2023-02-05-23-58-02 6.jpg','2023/PHOTO-2023-02-05-23-58-02 6.jpg','imagen','Captura de pantalla de una ventana flotante de chat en la plataforma Facebook Messenger. La conversación muestra un intercambio de mensajes entre el usuario del dispositivo y un contacto identificado como ''Hanselo Rojas Fig...'', quien presenta una relación de confianza e intimidad con el receptor.',replace('Hanselo Rojas Fig...\nActivo(a) hace 1 h\n[Hanselo]: Listo, dalo por hecho!\n[Usuario]: Cuando llegas?\n[Hanselo]: Si, me gustó arruyarte y verte dormir\n[Hanselo]: El viernes, deja compro el boleto\n[Usuario]: jajaja\n[Hanselo]: Y te paso el i ↓ rio','\n',char(10)),NULL,'vinculo_identidad, desarticulacion_coartada','Ninguna',8,'La evidencia confirma una relación íntima y planes de viaje conjuntos entre la demandada y Hansel Oliver Rojas Figueroa. Este hallazgo es fundamental para desvirtuar declaraciones previas de la madre sobre su situación sentimental y disponibilidad para el cuidado de la menor. El contenido sugiere desplazamientos constantes que podrían coincidir con periodos de desatención a la adolescente I.A.L.','Hanselo Rojas Figueroa (Hansel Oliver Rojas Figueroa), Viridiana López Valenzuela (presunta receptora de los mensajes)','Artículos 414 Bis y 416 del Código Civil para la Ciudad de México, relativos al cumplimiento de las obligaciones de crianza y la preservación de un entorno familiar estable y transparente.','{"sujeto_interés": "Hansel Oliver Rojas Figueroa", "hecho_relevante": "Planificación de viaje (''compro el boleto'') y acreditación de pernocta/intimidad (''arruyarte y verte dormir'')."}','APROBADO. Es una prueba clave para identificar a terceros que cohabitan o influyen en el entorno de la menor y para contrastar la veracidad del estilo de vida declarado por la demandada.','2026-04-04 01:15:43');
INSERT INTO hallazgos_proactivos VALUES(25,266,'7aff9d151f33256ad5f108c2a54b2ad283603644353e8db02567b8be5bbb6b3a','PHOTO-2023-02-05-23-58-02 6.jpg','VLV/DESAPARICIÓN FEBRERO 2023/PHOTO-2023-02-05-23-58-02 6.jpg','imagen','Captura de pantalla de un dispositivo móvil mostrando una ventana de chat flotante de Facebook Messenger. La conversación ocurre entre la usuaria de la cuenta y un contacto registrado como ''Hanselo Rojas Fig...''. El tono de la conversación es de carácter íntimo y personal, sugiriendo una relación sentimental y planes de viaje.',replace('Hanselo Rojas Fig...\nActivo(a) hace 1 h\nHanselo: Listo, dalo por hecho!\nInterlocutora: Cuando llegas?\nHanselo: Si, me gustó arruyarte y verte dormir\nHanselo: El viernes, deja compro el boleto\nInterlocutora: jajaja\nHanselo: Y te paso el itinerario [itinerario inferido por contexto e iniciales]','\n',char(10)),NULL,'vinculo_identidad_desarticulacion_coartada','Ninguna',8,'La evidencia digital confirma una relación de naturaleza íntima entre la demandada y Hansel Rojas Figueroa, contradiciendo posibles argumentos de una relación estrictamente profesional. La mención de compra de boletos e itinerarios aporta elementos sobre la movilidad y el entorno convivencial de la custodia. Resulta relevante para desarticular coartadas relacionadas con el tiempo de cuidado efectivo de la menor I.A.L.','Hansel Rojas Figueroa, Viridiana López Valenzuela (interlocutora)','Artículos 414 bis y 444 del Código Civil para la Ciudad de México, relativos al cumplimiento de los deberes de crianza y la evaluación del entorno familiar idóneo.','{"hecho_expediente": "Vinculado al seguimiento de Hansel Oliver Rojas Figueroa como tercero que interfiere en la dinámica familiar o sirve de coartada para la demandada.", "patron": "Desarticulación de la fachada de ''asesor inmobiliario'' mediante la prueba de vínculos afectivos estrechos y viajes no reportados."}','APROBADO: Aporta sustento crítico para demostrar falsedad en declaraciones sobre el entorno de la menor y la presencia de terceros en el núcleo de custodia.','2026-04-04 01:20:15');
INSERT INTO hallazgos_proactivos VALUES(26,293,'97231bf2d9e72c79d920abc0ccfe93ff20bc3de272d636ec041210b1db803972','PHOTO-2023-02-05-23-58-02 11.jpg','2023/PHOTO-2023-02-05-23-58-02 11.jpg','imagen','Captura de pantalla de una conversación de Facebook Messenger mostrada en un dispositivo electrónico. Se observa un intercambio de mensajes entre un contacto registrado como ''Hanselo Rojas Fig...'' y la usuaria del dispositivo. El diálogo sugiere la planeación de un encuentro presencial con tintes personales o afectivos.',replace('Hanselo Rojas Fig...\nActivo(a) hace 1 h\n[Azul]: ESTAS SEGURO?\n[Gris]: De que?\n[Azul]: DE VENIR\n[Gris]: Si y de querer verte 100%\n[Azul]: yo sigo nerviosa\n[Gris]: Tranquila\n[Gris]: Soy amable\n[Campo de texto]: Aa','\n',char(10)),NULL,'vinculo_identidad_desarticulacion_coartada','Ninguna',8,'Se acredita el vínculo personal y la planeación de encuentros privados entre la demandada y el sujeto identificado como Hansel Oliver Rojas Figueroa. La naturaleza afectiva del chat (''querer verte 100%'') contradice la narrativa de una relación estrictamente profesional o inexistente. Esta evidencia es fundamental para el análisis del entorno de la menor y la transparencia de la demandada sobre sus convivencias.','Hansel Oliver Rojas Figueroa, Viridiana López Valenzuela (identificada por el género gramatical ''nerviosa'' y contexto de la cuenta)','Artículo 444 Bis del Código Civil para el Distrito Federal; Artículo 416 Ter sobre el derecho de los menores a un entorno estable y la veracidad en las declaraciones procesales.','{"patron_especifico": "Vínculo de identidad y desarticulación de coartada", "relevancia": "Desmonta la fachada de Hansel Rojas como simple ''asesor inmobiliario'', probando una relación íntima/personal que ha sido omitida o falseada ante la autoridad."}','APROBADO si construye sustento legal para CDMX 2026, dado que permite demostrar el ocultamiento de información relevante sobre el entorno habitacional y de convivencia de la adolescente.','2026-04-04 01:25:18');
INSERT INTO hallazgos_proactivos VALUES(27,293,'97231bf2d9e72c79d920abc0ccfe93ff20bc3de272d636ec041210b1db803972','PHOTO-2023-02-05-23-58-02 12.jpg','VLV/DESAPARICIÓN FEBRERO 2023/PHOTO-2023-02-05-23-58-02 12.jpg','imagen','Captura de pantalla de una conversación de Facebook Messenger mostrada en la pantalla de un dispositivo electrónico (tableta o monitor). La conversación se entabla entre el titular de la cuenta (presuntamente Viridiana López Valenzuela, dado el uso del adjetivo femenino ''nerviosa'') y un contacto identificado como ''Hanselo Rojas Fig...'' (Hansel Oliver Rojas Figueroa). El intercambio indica la planificación de un encuentro físico cercano entre ambos.',replace('Hanselo Rojas Fig... \nActivo(a) hace 1 h\n[Derecha]: ESTAS SEGURO?\n[Izquierda]: De que?\n[Derecha]: DE VENIR\n[Izquierda]: Si y de querer verte 100%\n[Derecha]: yo sigo nerviosa\n[Izquierda]: Tranquila\n[Izquierda]: Soy amable','\n',char(10)),NULL,'violencia_vicaria','Violencia Vicaria',9,'El archivo acredita un vínculo personal estrecho y la coordinación de un encuentro físico entre la demandada y Hansel Oliver Rojas Figueroa. Esta evidencia desvirtúa directamente cualquier pretensión de una relación puramente profesional (como ''asesor inmobiliario''), revelando el ocultamiento de una relación de convivencia ante la autoridad judicial. La comunicación confirma la presencia constante de este tercero en el entorno de la menor I.A.L.','Hansel Oliver Rojas Figueroa, Viridiana López Valenzuela','Artículos 323 Séptimus del Código Civil para la Ciudad de México en materia de Violencia Vicaria y ocultamiento de información relevante sobre el entorno de desarrollo del menor.','{"patron_identidad": "Se vincula directamente con el individuo Hansel Oliver Rojas Figueroa mencionado en el punto 6 de las instrucciones estratégicas.", "desarticulacion_alibi": "Desmonta la fachada de ''asesor inmobiliario'' al demostrar un interés personal y afectivo (''querer verte 100%'')."}','APROBADO: Es una prueba toral para demostrar la falta de probidad de la demandada respecto a las personas que introduce en el círculo de vida de la adolescente y desarticular defensas basadas en relaciones estrictamente profesionales.','2026-04-04 01:28:05');
INSERT INTO hallazgos_proactivos VALUES(28,NULL,'0f4e57ad04a1b94f5cf1369b33923fa535fb233237ed573914c5ec3fe1d4173f','PHOTO-2023-02-05-23-58-02 15.jpg','VLV/DESAPARICIÓN FEBRERO 2023/PHOTO-2023-02-05-23-58-02 15.jpg','imagen','Captura de pantalla de una conversación de Facebook Messenger visualizada en un monitor. Se observa una ventana de chat activa entre la usuaria y un contacto identificado como ''Hanselo Rojas Figueroa''. La interfaz muestra una interacción reciente con el uso de emojis afectuosos y planes de continuar la comunicación por WhatsApp.',replace('[Encabezado de chat]\nHanselo Rojas Figueroa\nActivo(a) hace 1 h\n\n[Mensajes de la usuaria - burbujas azules]\njajaja\nok, sin mordida\nvoy a salir, ahora WhatsApp\nSi\n\n[Mensajes de Hanselo - burbujas grises]\nJaja ok\nCon cuidado\n😘😘😘😘\nYo le daré un rato al trabajo','\n',char(10)),NULL,'vinculo_identidad_coartada','Ninguna',8,'El documento acredita una relación de confianza y cercanía afectiva entre la demandada y Hanselo Rojas Figueroa, evidenciada por el uso de emojis de beso y la coordinación de actividades. Esta prueba es fundamental para desarticular la coartada que pretende presentar a dicho sujeto únicamente como un contacto profesional (asesor inmobiliario). Se establece la migración de la charla a WhatsApp para evasión de monitoreo en plataformas abiertas.','Hanselo Rojas Figueroa, Viridiana López Valenzuela (propietaria de la cuenta de origen)','Artículo 323 Septimus del Código Civil para el Distrito Federal; Artículos 210-A y 324 del Código de Procedimientos Civiles para la CDMX en materia de valoración de pruebas tecnológicas.','{"sujeto_interes": "Hanselo Rojas Figueroa", "relevancia": "Desmonta la fachada de ''asesor inmobiliario'' al mostrar un vínculo afectivo/personal directo con la demandada."}','APROBADO. Es una prueba clave para demostrar la existencia de un vínculo cercano con Hanselo Rojas Figueroa, lo cual es vital para el análisis de entorno del menor y la veracidad de las declaraciones de la madre.','2026-04-04 01:30:32');
INSERT INTO hallazgos_proactivos VALUES(29,311,'134cd58ba5d73981955c3dde7a17dadb594d57c8746724f6eefb1a1222a1705b','PHOTO-2023-02-05-23-58-02 9.jpg','VLV/DESAPARICIÓN FEBRERO 2023/PHOTO-2023-02-05-23-58-02 9.jpg','imagen','Fotografía de una pantalla (posiblemente tableta) que muestra una interfaz de red social. En primer plano, se observa una ventana flotante de chat de Facebook Messenger con el contacto ''Hanselo Rojas Figueroa''. La conversación muestra un mensaje de texto entrante, una secuencia de emojis de afecto y un archivo adjunto que parece ser una captura de pantalla de un sitio web de transacciones o reservaciones. Al fondo, se aprecia publicidad de SHEIN México.',replace('Hanselo Rojas Fig...\nActivo(a) hace 1 h\nSi me siento honrado con todo eso!!\n🥰🥰🥰🥰\nSHEIN Mexico\nshein.com.mx\nAa','\n',char(10)),NULL,'vínculo_de_identidad','Ninguna',7,'Se identifica comunicación directa y reciente con el sujeto Hanselo Rojas Figueroa, mostrando un tono de confianza y el intercambio de documentos digitales. Esta evidencia es clave para establecer el vínculo de identidad y convivencia del tercero con la demandada, contradiciendo posibles coartadas sobre su rol en el entorno de la menor.','Hanselo Rojas Figueroa','Código Civil para el Distrito Federal, Artículos 414 y 416, relativos al entorno de crianza y el interés superior del menor.','{"sujeto_interes": "Hansel Oliver Rojas Figueroa", "evidencia_documental": "Captura de pantalla enviada en el chat que sugiere gestión de viajes o trámites compartidos."}','APROBADO. Es fundamental para acreditar el vínculo con Hansel Rojas Figueroa y desarticular la coartada de ''asesor inmobiliario'' si se demuestra una relación personal estrecha que afecta la transparencia procesal.','2026-04-04 01:35:26');
INSERT INTO hallazgos_proactivos VALUES(30,288,'867aa7836ff0cd09a5753c91153defeb527f66ea9b21a830148b609a58ba8ecd','PHOTO-2023-02-05-23-58-02 12.jpg','2023/PHOTO-2023-02-05-23-58-02 12.jpg','imagen','Captura de pantalla de una interfaz de chat de Facebook Messenger. La conversación se desarrolla entre un usuario identificado como ''Hanselo Rojas Fig...'' (perfil con fotografía de un hombre) y la demandada (burbujas azules a la derecha). El entorno muestra un tono de confianza e informalidad personal.',replace('Hanselo Rojas Fig...\nActive(a) hace 1 h\n\nHanselo: No presionaremos nadal\nHanselo: Ni forzaremos nada\nDemandada: ok\nHanselo: Si lo quieres a la hora que tu te quieras ir sin probelma\nHanselo: No me enojaré\nHanselo: Solo me dejas completo y en un lugar con gente jajaja\nAa','\n',char(10)),NULL,'vinculo_identidad','Ninguna',7,'El archivo acredita de forma indiciaria un vínculo personal de confianza y proximidad entre la demandada y el sujeto identificado como Hanselo Rojas Figueroa. La naturaleza de los mensajes sugiere una relación que trasciende lo profesional, siendo relevante para el patrón de desarticulación de coartada del tercero.','Hanselo Rojas Figueroa, Viridiana López Valenzuela (interlocutora implícita)','Artículos 940 y 941 del Código de Procedimientos Civiles para la CDMX en relación con la idoneidad del entorno familiar y el interés superior del menor.','{"patron_identidad": "Se vincula directamente con el seguimiento del sujeto Hanselo Oliver Rojas Figueroa para desvirtuar su supuesta relación meramente laboral con la demandada.", "contexto": "Refuerza la línea de investigación sobre el ocultamiento de la dinámica de vida real de la demandada frente a la autoridad judicial."}','APROBADO si construye sustento legal para CDMX 2026, ya que permite individualizar y acreditar la relación estrecha de la madre con un tercero que influye en el entorno de la menor.','2026-04-04 01:38:05');
INSERT INTO hallazgos_proactivos VALUES(31,257,'e8a6126ac1900a6f17e9cac0e4e0bfb52c53285e8d567622a49c66a80e1117be','PHOTO-2023-02-05-23-58-02 3.jpg','2023/PHOTO-2023-02-05-23-58-02 3.jpg','imagen','Captura de pantalla de un dispositivo móvil mostrando una ventana flotante (chat head) de Facebook Messenger. La conversación se desarrolla entre el usuario del dispositivo y un contacto identificado como ''Hanselo Rojas Fig...''. De fondo se aprecia una interfaz de reproducción de música y el dispositivo descansa sobre una superficie de color amarillo.',replace('Hanselo Rojas Fig... \nActivo(a) hace 1 h\n\n[Hanselo]: Pues si, playa, malecón y restaurantes\n[Hanselo]: 1 acuario y bares jajaja\n[Emisor]: Y Netflix\n[Emisor]: y cama\n[Emisor]: y helado\n[Emisor]: allá o aquí encontraremos que hacer\n\nAa','\n',char(10)),NULL,'vinculo_identidad_desarticulacion_coartada','Ninguna',7,'La evidencia establece un vínculo directo y una relación de confianza/intimidad entre la demandada y Hansel Oliver Rojas Figueroa. Los mensajes corroboran planes de recreación y viajes (''playa'', ''malecón'', ''allá o aquí''), lo que permite desarticular posibles coartadas sobre el paradero de la madre o la naturaleza de su relación con dicho sujeto. Este elemento es clave para rastrear el entorno convivencial al que se expone a la menor I.A.L.','Hanselo Rojas Fig... (Hansel Oliver Rojas Figueroa), Emisor (presuntamente Viridiana López Valenzuela)','Artículos 323 Septimus del Código Civil para la CDMX y principios de valoración de la prueba electrónica respecto al entorno de cuidado del menor.','{"sujeto_interes": "Hansel Oliver Rojas Figueroa", "contexto": "Desmentido de alibi legal como ''asesor inmobiliario'' al mostrar una dinámica de ocio y pareja."}','APROBADO ya que vincula directamente a la demandada con el tercero Hansel Rojas, permitiendo cuestionar la veracidad de sus declaraciones sobre su situación sentimental y planes de movilidad que afectan la estabilidad de la menor.','2026-04-04 01:44:46');
INSERT INTO hallazgos_proactivos VALUES(32,257,'e8a6126ac1900a6f17e9cac0e4e0bfb52c53285e8d567622a49c66a80e1117be','PHOTO-2023-02-05-23-58-02 3.jpg','VLV/DESAPARICIÓN FEBRERO 2023/PHOTO-2023-02-05-23-58-02 3.jpg','imagen','Captura de pantalla de un dispositivo móvil mostrando una ventana flotante de chat (estilo Facebook Messenger). La conversación se entabla entre un usuario identificado como ''Hanselo Rojas Fig...'' y la parte receptora. Los mensajes sugieren la planificación de actividades de ocio y convivencia íntima, mencionando viajes y estancia compartida.',replace('Hanselo Rojas Fig...\nActivo(a) hace 1 h\n\nHanselo Rojas Fig...: Pues si, playa, malecón y restaurantes\nHanselo Rojas Fig...: 1 acuario y bares jajaja\n\nReceptor (azul): Y Netflix\nReceptor (azul): y cama\nReceptor (azul): y helado\nReceptor (azul): allá o aquí encontraremos que hacer\n\n[Iconos de interfaz: +, imagen, stickers, GIF, micrófono, campo de texto ''Aa'', emoji, like]','\n',char(10)),'2023-02-05 23:58','violencia_vicaria, desacato_visitas','Violencia Vicaria',8,'La evidencia confirma una relación de confianza e intimidad entre la demandada y Hansel Oliver Rojas Figueroa, evidenciada por planes de viaje y menciones de convivencia privada (''cama''). Este hallazgo es fundamental para desarticular la coartada de una relación meramente profesional y rastrear posibles omisiones en el régimen de visitas por viajes no reportados.','Hansel Oliver Rojas Figueroa, Viridiana López Valenzuela (presunta receptora)','Artículo 323 Séptimus del Código Civil para el Distrito Federal (Violencia Vicaria); Artículo 416 Ter del mismo ordenamiento sobre el interés superior del menor y el entorno de convivencia.','{"identidad_tercero": "Vínculo directo con Hansel Oliver Rojas Figueroa, permitiendo contrastar sus actividades con los periodos de convivencia solicitados por el padre.", "desarticulacion_coartada": "Contradice la posible narrativa de la madre sobre la ausencia de parejas sentimentales o viajes que interfieran con la estabilidad de la adolescente."}','APROBADO ya que permite acreditar la existencia de un entorno de vida de la madre no revelado al juzgado, esencial para evaluar la estabilidad del núcleo de custodia bajo el concepto de Autonomía Progresiva de la menor.','2026-04-04 01:47:46');
INSERT INTO hallazgos_proactivos VALUES(33,271,'68bd90ac4bbcaceb53b64e98a52fe2f2c081d7faeb135e0bd43eee79559c7401','PHOTO-2023-02-05-23-58-02 7.jpg','2023/PHOTO-2023-02-05-23-58-02 7.jpg','imagen','Captura de pantalla de un chat de Facebook Messenger entre un usuario no identificado (presuntamente la demandada o la menor) y un contacto guardado como ''Hanselo Rojas Fig...''. La interfaz muestra una conversación informal sobre la coordinación de un encuentro y el intercambio de un ''itinerario''. El entorno del dispositivo sugiere una navegación en una red social antes de capturar el mensaje flotante.',replace('Hanselo Rojas Fig...\nActivo(a) hace 1 h\nHanselo: Y te paso el itinerario\nUsuario: si\nUsuario: para pasar por ti\nHanselo te respondió: para pasar por ti\nHanselo: Siiiii 😍 😅\nUsuario: no se te olviden tus riñones\nUsuario: jajaja','\n',char(10)),NULL,'vinculo_identidad_desarticulacion_coartada','Ninguna',7,'La evidencia establece comunicación directa y planificación logística entre un tercero, Hanselo Rojas Figueroa, y la interlocutora. La mención de un ''itinerario'' y la coordinación para ''pasar por él'' contradicen posibles coartadas sobre la naturaleza estrictamente profesional de su relación. El tono informal y de confianza refuerza el vínculo estrecho entre las partes.','Hanselo Rojas Figueroa, Remitente no identificado (presuntamente Viridiana López Valenzuela)','Código Civil CDMX, Artículo 444 (pérdida de patria potestad por conductas que comprometen el entorno del menor); Artículos 210-A y 402 del Código de Procedimientos Civiles para la CDMX (reconocimiento de evidencia digital).','{"vinculo_sujeto": "Hanselo Rojas Figueroa", "relevancia_fáctica": "Desarticula la coartada de relación meramente laboral y confirma planes de traslado/viajes conjuntos (itinerario)."}','APROBADO si construye sustento legal para CDMX 2026, dado que acredita la existencia de una relación personal y planificación de actividades fuera del ámbito familiar con el sujeto identificado como Hansel Oliver Rojas Figueroa.','2026-04-04 01:52:54');
INSERT INTO hallazgos_proactivos VALUES(34,292,'d8798102375aeb6ca926f80afbdbe49094bd0b334b57abf6156333947149f629','PHOTO-2023-02-05-23-58-02 14.jpg','VLV/DESAPARICIÓN FEBRERO 2023/PHOTO-2023-02-05-23-58-02 14.jpg','imagen','Captura de pantalla de una conversación de chat en la plataforma Facebook Messenger. Se observa una interacción de carácter personal e informal entre un contacto guardado como ''Hanselo Rojas Fig...'' y la parte demandada. El contenido de los mensajes y el uso de emojis denotan una relación de confianza, cercanía e intimidad.',replace('Hanselo Rojas Fig... Activo(a) hace 1 h\nHanselo: Solo me dejas completo y en un lugar con gente jajaja\nDemandada: jajaja\nDemandada: ok, sin mordida\nDemandada: voy a salir, ahora WhatsApp\nHanselo: Jaja ok\nHanselo: Con cuidado\nHanselo: 😘😘😘😘\nHanselo: Yo le daré un rato al trabajo','\n',char(10)),NULL,'vinculo_identidad','Ninguna',8,'La evidencia acredita un vínculo afectivo estrecho entre la demandada y Hanselo Rojas Figueroa, caracterizado por lenguaje lúdico de índole personal (''sin mordida'') y el intercambio de afectos (emojis de beso). Esta comunicación es fundamental para desarticular la coartada que pretende presentar a dicho tercero únicamente como un ''asesor inmobiliario'', revelando un ocultamiento de la dinámica real del entorno doméstico de la menor I.A.L.','Hanselo Rojas Figueroa, Viridiana López Valenzuela','Artículos 414 y 416 del Código Civil para el Distrito Federal (Interés superior del menor y estabilidad del entorno familiar).','{"patron_6_identidad": "Se vincula directamente con la identificación de Hansel Oliver Rojas Figueroa como pareja sentimental o conviviente de la demandada, invalidando sus testimonios previos sobre una relación meramente profesional."}','APROBADO si construye sustento legal al demostrar la falta de veracidad de la demandada sobre las figuras de cuidado y compañía que rodean a la adolescente.','2026-04-04 02:07:46');
INSERT INTO hallazgos_proactivos VALUES(35,NULL,'b32ace18818a94d8009a2c1e9f5a0aa63e39ed8d7c08c8830a76bed91e3f0009','ANZORENA LOPEZ IO 2do parcial.pdf','Documentos IO/IO UVM/CALIFICACIONES/ANZORENA LOPEZ IO 2do parcial.pdf','documento','Documento digital en formato PDF que constituye un ''Informe de Desempeño Académico'' emitido por la Universidad del Valle de México (UVM), Campus Preparatoria UNAM. El reporte detalla las calificaciones del primer y segundo parcial del ciclo escolar 2025-2026 de la menor I.A.L. Se observa una tendencia académica crítica con reprobación masiva en el segundo parcial.','UNIVERSIDAD DEL VALLE DE MEXICO. NOMBRE DEL PADRE O TUTOR: RENE IVAN ANZORENA HERNANDEZ. NOMBRE DEL ESTUDIANTE: ANZORENA LOPEZ IO. PROGRAMA ACADEMICO: PUNM01U25 PREPARATORIA UNAM. DIBUJO II: 0.01 (1er P) 0.01 (2do P). LOGICA: 3.59 (1er P) 0.00 (2do P). LENGUA ESPAÑOLA: 6.77 (1er P) 0.48 (2do P). FISICA III: 3.11 (1er P) 0.49 (2do P). MATEMATICAS IV: 5.80 (1er P) 2.00 (2do P). HISTORIA UNIVERSAL III: 3.80 (1er P) 0.86 (2do P). PROMEDIO ANUAL: 4.01. NOTA: La Calificación Mínima Aprobatoria es de : 6.','2026-01-12 11:23','inaccion_educativa','Ninguna',9,'El informe académico revela un colapso en el desempeño escolar de la menor I.A.L., con un promedio general de 4.01 y calificaciones de casi cero en materias troncales durante el segundo parcial. Estos resultados objetivos evidencian una falta absoluta de supervisión y acompañamiento pedagógico por parte de la madre custodia. La evidencia sugiere un estado de abandono educativo que compromete el desarrollo integral de la adolescente.','René Iván Anzorena Hernández, I.A.L. (Anzorena López IO)','Artículos 414 Bis y 444 fracción IV del Código Civil para la Ciudad de México (incumplimiento de deberes de crianza); Artículo 103 de la Ley General de los Derechos de Niñas, Niños y Adolescentes.','{"contexto_escolar": "Vinculado proactivamente con la posible influencia de terceros (''Valeria'') en el entorno de la madre que desplazan la atención prioritaria hacia la educación de la menor.", "negligencia": "El desplome de calificaciones entre el 1er y 2do parcial coincide temporalmente con el periodo de mayor conflicto procesal."}','APROBADO. Es una prueba documental pública/institucional que demuestra objetivamente la negligencia en los deberes de cuidado y educación, causal directa para la Pérdida de la Patria Potestad.','2026-04-06 13:56:05');
INSERT INTO hallazgos_proactivos VALUES(36,NULL,'d6801627393dae61ff478df03fe69f0dd3ad9fb71fa60848ccc0ebdab3b8870f','boleta-2024-07-16.pdf','Documentos IO/IO QUEEN MARY/boleta-2024-07-16.pdf','documento','Documento digital en formato PDF que corresponde a la Boleta de Evaluación oficial emitida por la Secretaría de Educación Pública (SEP) y la Autoridad Educativa Federal en la Ciudad de México (AEFCM). El documento certifica las calificaciones de la menor I.A.L. para el segundo grado de educación secundaria durante el ciclo escolar 2023-2024 en el colegio privado ''REINA MARÍA''.','SISTEMA EDUCATIVO NACIONAL. CIUDAD DE MÉXICO. BOLETA DE EVALUACIÓN 2o GRADO DE EDUCACIÓN SECUNDARIA CICLO ESCOLAR 2023-2024. NOMBRE DE LA ALUMNA: IO ANZORENA LOPEZ. CURP: AOLI101222MMCNPXA0. NOMBRE DE LA ESCUELA: REINA MARÍA. CCT: 09PES0200K. PROMÉDIOS: ESPAÑOL 9.0, INGLÉS 7.6, ARTES (MÚSICA) 8.3, MATEMÁTICAS 6.6, FÍSICA 8.0, HISTORIA 8.6, FORMACIÓN CÍVICA Y ÉTICA 8.3, TECNOLOGÍA (INFORMÁTICA) 10, EDUCACIÓN FÍSICA 9.0. ASISTENCIAS: 190. PROMEDIO FINAL DE GRADO: 8.3. Lugar y fecha de expedición: Cuauhtémoc, Ciudad de México 16/07/2024. Firma: RENÉ MARIO FRANCO RODRÍGUEZ, DIRECTOR GENERAL DE OPERACIÓN DE SERVICIOS EDUCATIVOS.','2024-07-16 00:00','inaccion_educativa','Ninguna',8,'Se analiza boleta de evaluación del ciclo 2023-2024 de la menor I.A.L., arrojando un promedio general de 8.3. Se identifica un desempeño bajo en la asignatura de Matemáticas (6.6), lo cual constituye un indicador de alerta sobre la supervisión académica efectiva. El documento es auténtico y cuenta con firma electrónica avanzada de la AEFCM.','IO ANZORENA LOPEZ, RENÉ MARIO FRANCO RODRÍGUEZ','Artículos 411, 414 y 416 Ter del Código Civil para el Distrito Federal, relativos a la obligación de quienes ejercen la patria potestad de garantizar la formación académica y el desarrollo integral de los menores.','{"academico_emocional": "La calificación de 6.6 en Matemáticas debe cruzarse con las bitácoras de asistencia y las menciones de ''Valeria'' para determinar si el bajo rendimiento coincide con periodos de interferencia o falta de supervisión por parte de la demandada."}','APROBADO. Sirve como línea base probatoria para demostrar el estado del derecho a la educación de la menor y evaluar si la custodia de la madre está garantizando el máximo aprovechamiento escolar.','2026-04-06 14:00:27');
INSERT INTO hallazgos_proactivos VALUES(37,NULL,'40b0a66485a709d5bc76361ba64b7748f2f4f03b46f32a87c714078cfdb19adc','curp IO.pdf','Documentos IO/curp IO.pdf','documento','Documento digital en formato PDF que corresponde a una Constancia de la Clave Única de Registro de Población (CURP) certificada, emitida por la Secretaría de Gobernación (RENAPO). El documento incluye logotipos oficiales del Gobierno de México y una carta firmada por el entonces Secretario de Gobernación, Adán Augusto López Hernández.','IO ANZORENA LOPEZ. 109005201003210. AOLI101222MMCNPXA0. CURP Certificada: verificada con el Registro Civil. Ciudad de México, a 01 de febrero de 2022. Entidad de registro: DISTRITO FEDERAL. El derecho a la identidad está consagrado en nuestra Constitución. En la Secretaría de Gobernación trabajamos todos los días para garantizar que las y los mexicanos gocen de este derecho plenamente.','2022-02-01 00:00','sin_relevancia_procesal','Ninguna',5,'Documento público que acredita la identidad legal y la filiación de la menor I.A.L. con el apellido paterno ''Anzorena'', sin presentar alteraciones. Es una prueba de identidad necesaria para el expediente, pero no aporta elementos directos de conducta omisiva o violenta por sí misma.','I.A.L. (referida como IO Anzorena Lopez), Adán Augusto López Hernández','Artículo 4o de la Constitución Política de los Estados Unidos Mexicanos (Derecho a la identidad), Artículo 384 del Código Civil para el Distrito Federal (Prueba de la filiación).','{"filiacion": "Confirma el vínculo legal con el actor René Iván Anzorena Hernández al mantener el apellido paterno.", "temporalidad": "Documento emitido en 2022, año de inicio del expediente 1784/2022."}','APROBADO si construye sustento legal para CDMX 2026, ya que es indispensable para acreditar la personalidad de la menor y la legitimación pasiva/activa en el proceso de patria potestad.','2026-04-06 14:02:37');
INSERT INTO hallazgos_proactivos VALUES(38,NULL,'7d41fcf8218234764576a1ed22fcb74f649b43c23c51567ca365374df7bb0b6f','boleta-2023-07-26.pdf','Documentos IO/IO QUEEN MARY/boleta-2023-07-26.pdf','documento','Documento oficial en formato PDF que corresponde a la Boleta de Evaluación del Sistema Educativo Nacional para el primer grado de educación secundaria. El documento certifica el rendimiento académico de la menor I.A.L. durante el ciclo escolar 2022-2023 en el colegio ''REINA MARÍA''. Se observa un desempeño académico irregular con calificaciones mínimas aprobatorias en materias fundamentales como Matemáticas y Ciencias.','SISTEMA EDUCATIVO NACIONAL. BOLETA DE EVALUACIÓN. 1er GRADO DE EDUCACIÓN SECUNDARIA CICLO ESCOLAR 2022-2023. DATOS DE LA ALUMNA: ANZORENA LOPEZ IO. CURP: AOLI101222MMCNPXA0. ESCUELA: REINA MARÍA. CCT: 09PES0200K. CALIFICACIONES: LENGUA MATERNA (ESPAÑOL): 8.6; MATEMÁTICAS: 6.6; CIENCIAS (BIOLOGÍA): 7.0; HISTORIA: 7.3; GEOGRAFÍA: 8.6; FORMACIÓN CÍVICA Y ÉTICA: 9.0; TECNOLOGÍA: 8.3; EDUCACIÓN FÍSICA: 9.0; LENGUA EXTRANJERA (INGLÉS): 8.6; ARTES (MÚSICA): 9.3; INFORMÁTICA: 9.0. PROMEDIO FINAL DE GRADO: 8.2. Lugar y fecha de expedición: Cuauhtémoc, Ciudad de México 26/07/2023. Autoridad educativa: RENÉ MARIO FRANCO RODRÍGUEZ.','2023-07-26 00:00','inaccion_educativa','Ninguna',7,'Documento oficial que acredita el aprovechamiento académico de la menor bajo la custodia de la demandada. Se detecta un rendimiento crítico en Matemáticas (6.6) y Ciencias (7.0), lo que sugiere una posible falta de supervisión académica o apoyo pedagógico en el hogar. La evidencia es relevante para evaluar el cumplimiento de los deberes de crianza y formación educativa por parte de la madre custodia.','I.A.L. (menor), ANZORENA LÓPEZ IO, RENÉ MARIO FRANCO RODRÍGUEZ (Director General de Operación de Servicios Educativos)','Artículos 414 y 444 Fracción IV del Código Civil para el Distrito Federal; Artículo 103 de la Ley General de los Derechos de Niñas, Niños y Adolescentes (LGDNNA).','{"hecho_relacionado": "Se vincula con las alegaciones del actor sobre la baja escolar y falta de seguimiento en tareas por parte de Viridiana López Valenzuela.", "vulnerabilidad": "El bajo desempeño en materias troncales coincide con el periodo de mayor conflicto procesal entre los progenitores."}','APROBADO. Es una prueba documental pública que permite contrastar la calidad de la educación y supervisión recibida por la menor bajo la guarda de la demandada en 2023.','2026-04-06 14:06:57');
INSERT INTO hallazgos_proactivos VALUES(39,NULL,'e6e420ff8662608da92321926d27001b7192eac92212a4af4255222ae2ccfb98','comprobanteAOLI101222MMCNPXA0.pdf','Documentos IO/comprobanteAOLI101222MMCNPXA0.pdf','documento','Comprobante oficial de preinscripción emitido por la Autoridad Educativa Federal en la Ciudad de México (AEFCM) a través del Sistema Anticipado de Inscripción y Distribución (SAID). El documento formaliza la solicitud de ingreso a primer grado de secundaria para el ciclo escolar 2022-2023 de la menor I.A.L.','ESTE DOCUMENTO AMPARA LA SOLICITUD DE PREINSCRIPCIÓN A PRIMER GRADO DE EDUCACIÓN SECUNDARIA PARA EL CICLO ESCOLAR 2022-2023. FOLIO: 203. FECHA DE REGISTRO: 2022/02/15. NOMBRE DEL ASPIRANTE: ANZORENA LOPEZ IO. CURP: AOLI101222MMCNPXA0. DOMICILIO: RIO USSURI 25, COLONIA CUAUHTÉMOC, CUAUHTÉMOC, CIUDAD DE MÉXICO. OPCIONES SOLICITADAS: 1. ESCUELA SECUNDARIA ANEXA A LA NORMAL SUPERIOR DE MÉXICO, 2. JUSTO SIERRA, 3. REPÚBLICA DE FRANCIA. TELÉFONO(S): PRINCIPAL: 5554511232 ALTERNO CELULAR: 5572247939. CORREO ELECTRÓNICO: reneanzorena@gmail.com ADICIONAL: art.veneno@icloud.com.','2022-02-15 00:00','desarticulacion_coartada, fraude_domiciliar','Ninguna',8,'El documento demuestra que en febrero de 2022, el actor (René Iván Anzorena Hernández) ejercía activamente la responsabilidad parental, gestionando personalmente el trámite educativo de la menor. El registro de su correo electrónico personal y teléfonos como contactos principales desvirtúa posibles acusaciones de abandono o desatención. Asimismo, fija un domicilio de referencia en la Colonia Cuauhtémoc para el proceso de asignación escolar.','ANZORENA LOPEZ IO (I.A.L.), René Iván Anzorena Hernández (vía correo electrónico)','Artículos 411, 414 y 416 del Código Civil para la Ciudad de México relativos al ejercicio de la patria potestad y el cumplimiento de las obligaciones de crianza y educación.','{"gestion_escolar": "Vincula al padre directamente con la toma de decisiones educativas en el periodo previo al conflicto agudo.", "domicilio": "Establece el domicilio de Rio Ussuri 25 como base para la asignación por cercanía, lo cual debe contrastarse con el patrón de fraude domiciliar de la demandada."}','APROBADO. Constituye prueba documental pública para acreditar el involucramiento proactivo del padre en la educación de la menor y establece una línea de tiempo contra alegatos de abandono.','2026-04-06 14:09:08');
INSERT INTO hallazgos_proactivos VALUES(40,NULL,'81e7deaa746ad3c494e3449f0636d39dd95f9d696438b9938a3e04e369810456','ANZORENA LOPEZ IO 3er parcial.pdf','Documentos IO/IO UVM/CALIFICACIONES/ANZORENA LOPEZ IO 3er parcial.pdf','documento','Informe de desempeño académico oficial emitido por la Universidad del Valle de México (UVM), Campus San Rafael, perteneciente a la menor I.A.L. El documento muestra una trayectoria de calificaciones en declive crítico durante el ciclo escolar 2026, con un promedio general de 4.01 y múltiples materias con calificación de 0.01 o 0.00 en el tercer parcial, lo que denota abandono escolar de facto.','UNIVERSIDAD DEL VALLE DE MEXICO CAMPUS SAN RAFAEL FECHA: 13-03-2026 HORA: 09:27 INFORME DE DESEMPEÑO ACADEMICO NUM-CTA 010223648 NOMBRE DEL ESTUDIANTE ANZORENA LOPEZ I.O. ... PROMEDIOS Y TOTALES DEL SEMESTRE: 4.01. Materias con 0.01 en 3er Parcial: INGLES IV, DIBUJO II, FISICA III. Materias con 0.00 en 3er Parcial: LOGICA, LENGUA ESPAÑOLA, VALORES ETICOS, HISTORIA UNIVERSAL.','2026-03-13 09:27','inaccion_educativa, higiene_lifestyle','Violencia Psicoemocional, Institucional',10,'Se documenta un estado de abandono educativo severo de la adolescente I.A.L., quien presenta calificaciones nulas (0.00 y 0.01) en la mayoría de sus asignaturas del tercer parcial. Esta evidencia técnica demuestra una omisión absoluta de los deberes de cuidado y supervisión académica por parte de la madre custodia. El documento oficial de la UVM acredita que la menor se encuentra en riesgo de pérdida del año escolar bajo la guarda de la demandada.','I.A.L. (Estudiante), René Iván Anzorena Hernández (Padre/Tutor), Viridiana López Valenzuela (Madre custodia implícita)','Artículos 414 Bis, 416 y 444 Fracción IV del Código Civil para el Distrito Federal (incumplimiento reiterado de los deberes de crianza y educación); Ley General de los Derechos de Niñas, Niños y Adolescentes (Derecho a la educación).','{"escolar_vs_custodia": "El desplome académico coincide con el periodo de custodia exclusiva de la demandada, vinculando el ausentismo escolar con la falta de supervisión parental.", "riesgo_autonomia": "La baja académica compromete el principio de Autonomía Progresiva de la menor al limitar sus oportunidades futuras de desarrollo."}','APROBADO. Es una prueba documental pública/institucional irrefutable de negligencia en los deberes de crianza, fundamental para un juicio de pérdida de patria potestad en CDMX.','2026-04-06 14:11:17');
